I18N.register("es", {
  q: {
    "TPR1_01": ["¿Qué sigue? ◇, ◇◇, ◇◇◇, ◇◇◇◇, ?", "Cuente los diamantes en cada paso.", ["◇◇◇◇◇", "◇◇◇", "◇◇◇◇", "◇◇"], "A cada paso se le suma un rombo: 1, 2, 3, 4, entonces quedan 5 rombos."],
    "TPR1_02": ["¿Qué sigue? A, B, C, D, E, ?", "Piensa en el orden de las letras del abecedario.", ["F", "G", "D", "A"], "Son letras seguidas del abecedario; después de E viene F."],
    "TPR1_03": ["¿Qué sigue? 1, 2, 3, 4, 5, ?", "Cada número aumenta en el mismo paso.", ["6", "7", "5", "8"], "Cada número aumenta en 1, por lo que después del 5 viene el 6."],
    "TPR1_04": ["¿Qué sigue? 2, 4, 6, 8, ?", "Mira la diferencia entre números consecutivos.", ["10", "12", "9", "11"], "Los pasos son de 2 en 2. Después del 8, el siguiente número par es el 10."],
    "TPR1_05": ["¿Qué sigue? A, B, A, B, A, ?", "Fíjate en el patrón que alterna.", ["B", "A", "C", "D"], "El patrón alterna A y B sin parar; después de A viene B."],
    "TPR1_06": ["¿Qué sigue? □, □□, □□□, ?", "Cuente los cuadrados en cada paso.", ["□□□□", "□□", "□□□□□", "□□□"], "Se agrega un cuadrado a cada paso: 1, 2, 3, por lo que siguen 4 cuadrados."],
    "TPR1_07": ["¿Qué sigue? Z, Y, X, W, ?", "El alfabeto va al revés.", ["V", "tu", "x", "t"], "Las letras del alfabeto van al revés: Z, Y, X, W, V."],
    "TPR1_08": ["¿Qué sigue? 10, 20, 30, 40, ?", "Cada número aumenta en el mismo paso.", ["50", "45", "60", "55"], "Los pasos son del 10 al 10. Después de 40, el siguiente término es 50."],
    "TPR1_09": ["¿Qué sigue? 3, 6, 9, 12, ?", "Cada número aumenta en el mismo paso.", ["15", "14", "18", "13"], "Los pasos son de 3 en 3. Después de 12, el siguiente múltiplo de 3 es 15."],
    "TPR1_10": ["Completa la cuadrícula: 1, 3, 5/7, 9, 11/13, 15, ?", "Enumera los números impares en orden, fila por fila.", ["17", "16", "19", "18"], "La cuadrícula enumera números impares consecutivos: 1, 3, 5, 7,…, 15, 17."],
    "TPR1_11": ["¿Qué sigue? ★, ★★, ★★★, ★★★★, ?", "Cuenta las estrellas en cada paso.", ["★★★★★", "★★★★", "★★★", "★★★★★★"], "Se agrega una estrella a cada paso: 1, 2, 3, 4, por lo que le siguen 5 estrellas."],
    "TPR1_12": ["¿Qué sigue? 6, 12, 18, 24, ?", "Cada término es múltiplo del mismo número, ¿cuál?", ["30", "28", "36", "32"], "Los pasos son del 6 al 6. Después del 24, el siguiente múltiplo de 6 es 30."],
    "TPR1_13": ["¿Qué sigue? M, N, O, P, ?", "Son letras consecutivas del alfabeto.", ["q", "R", "norte", "S"], "Las letras continúan en orden alfabético: M, N, O, P, Q."],
    "TPR1_14": ["¿Qué sigue? 1, 1, 1, 1, ?", "¿El valor cambia alguna vez?", ["1", "2", "0", "3"], "Cada término es 1; el patrón es constante, por lo que el siguiente valor es 1."],
    "TPR1_15": ["¿Qué sigue? ♥, ♦, ♥, ♦, ♥, ?", "Se alternan dos símbolos.", ["♦", "♥", "♣", "♠"], "El patrón alterna corazón y diamante. Después del corazón viene el diamante."],
    "TPR1_16": ["¿Qué sigue? 8, 16, 24, 32, ?", "Mira la diferencia entre números consecutivos.", ["40", "36", "48", "38"], "Los pasos son del 8 al 8. Después de 32, el siguiente múltiplo de 8 es 40."],
    "TPR1_17": ["¿Qué sigue? ♠, ♠♠, ♠♠♠, ?", "Cuente los símbolos del club en cada paso.", ["♠♠♠♠", "♠♠", "♠♠♠", "♠♠♠♠♠"], "Se agrega un trébol a cada paso: 1, 2, 3, por lo que hay 4 tréboles."],
    "TPR1_18": ["¿Qué sigue? 30, 27, 24, 21, ?", "Los números disminuyen en un paso fijo.", ["18", "20", "15", "19"], "Cada número disminuye en 3. Después de 21, el siguiente valor es 18."],
    "TPR1_19": ["¿Qué sigue? 7, 14, 21, 28, ?", "Todo número es múltiplo del mismo número.", ["35", "36", "32", "42"], "Los pasos son del 7 al 7. Después del 28, el siguiente múltiplo de 7 es 35."],
    "TPR1_20": ["Completa la cuadrícula: 2, 4, 6/8, 10, 12/14, 16, ?", "Enumera los números pares fila por fila.", ["18", "20", "17", "19"], "La cuadrícula enumera números pares consecutivos: 2, 4, 6, 8,…, 16, 18."],
    "TPR2_01": ["¿Qué sigue? X, XY, XYX, XYXY, ?", "En cada paso se añade un carácter más, alternando entre X e Y.", ["XYXYX", "XYXYY", "YXYXY", "XYXY"], "El patrón crece mediante suma alternada: el quinto término tiene 5 caracteres: XYXYX."],
    "TPR2_02": ["Cuadrícula: 3, 6, 9/5, 10, 15/8, 16,?", "Observa cómo se relaciona cada fila con el primer número de la fila.", ["24", "20", "18", "32"], "Cada fila multiplica el primer número por 1, 2, 3. Fila 3: 8×1=8, 8×2=16, 8×3=24."],
    "TPR2_03": ["¿Qué sigue? AA, BB, CC, DD, ?", "Cada pareja usa la siguiente letra del alfabeto.", ["EE", "FF", "DE", "AB"], "Cada término es una letra consecutiva duplicada: A, B, C, D, E → EE."],
    "TPR2_04": ["¿Qué sigue? 1, 3, 5, 7, 9, ?", "Son números impares.", ["11", "10", "13", "12"], "La cadena enumera números impares consecutivos. Después del 9, el siguiente número impar es el 11."],
    "TPR2_05": ["¿Qué sigue? ○●, ○●○, ○●○●, ○●○●○, ?", "En cada paso se agrega una forma más, alternando ○ y ●.", ["○●○●○●", "○●○●○○", "●○●○●○", "○●○●●○"], "El patrón crece una forma en cada paso, alternando ○ y ●. Lo siguiente tiene 6 formas: ○●○●○●."],
    "TPR2_06": ["¿Qué sigue? 2, 6, 10, 14, ?", "Encuentra la diferencia constante entre los términos.", ["18", "16", "20", "15"], "Cada número aumenta en 4. Después del 14, el siguiente valor es 18."],
    "TPR2_07": ["¿Qué sigue? AB, CD, EF, GH, ?", "Cada par usa las siguientes dos letras consecutivas.", ["IJ", "JK", "hola", "kl"], "Las parejas recorren el alfabeto de dos letras a la vez: AB, CD, EF, GH, IJ."],
    "TPR2_08": ["Cuadrícula: 1, 3, 5/2, 4, 6/3, 5,?", "Cada fila comienza con un número mayor y agrega el mismo paso.", ["7", "8", "6", "9"], "Cada fila enumera tres números que aumentan en 2. La fila 3 comienza en 3: 3, 5, 7."],
    "TPR2_09": ["¿Qué sigue? ○, ■, ○, ■, ○, ■, ?", "En el ciclo se repiten dos formas.", ["○", "■", "△", "◇"], "El patrón alterna ○ y ■. Después de ■ sigue ○."],
    "TPR2_10": ["¿Qué sigue? 20, 17, 14, 11, ?", "Los números disminuyen en una cantidad fija.", ["8", "9", "7", "10"], "Cada número disminuye en 3. Después del 11, el siguiente valor es 8."],
    "TPR2_11": ["¿Qué sigue? ABA, BCB, CDC, DED, ?", "Observa cómo se mueven las tres letras de cada grupo.", ["EFE", "FGF", "DEF", "EEE"], "Cada grupo sigue el patrón: letra, siguiente letra, misma primera letra; se desplaza un paso en cada grupo. Después del DED viene EFE."],
    "TPR2_12": ["Cuadrícula: 5, 10, 15/6, 12, 18/7, 14,?", "Cada fila multiplica el primer número por 1, 2 y 3.", ["21", "20", "24", "28"], "Fila 3: 7×1=7, 7×2=14, 7×3=21."],
    "TPR2_13": ["¿Qué sigue? 0, 2, 4, 6, 8,?", "Son números pares consecutivos que comienzan desde 0.", ["10", "12", "9", "11"], "La cadena enumera números pares: 0, 2, 4, 6, 8, 10."],
    "TPR2_14": ["¿Qué sigue? ○○, ■■, ○○, ■■, ?", "Los pares de formas se alternan.", ["○○", "■■", "○■", "■○"], "El patrón alterna pares: ○○, ■■, ○○, ■■, ○○."],
    "TPR2_15": ["¿Qué sigue? 3, 7, 11, 15, 19, ?", "Encuentra la diferencia común entre los términos.", ["23", "22", "21", "24"], "Cada número aumenta en 4. Después del 19, el siguiente valor es 23."],
    "TPR2_16": ["Cuadrícula: 1, 2, 3/2, 4, 6/3, 6,?", "Compara cada fila con la fila de arriba.", ["9", "8", "10", "12"], "La fila n multiplica 1, 2, 3 por n. Fila 3: 3×1=3, 3×2=6, 3×3=9."],
    "TPR2_17": ["¿Qué sigue? ¿XY, WX, VW, UV?", "Cada pareja retrocede una letra en el alfabeto.", ["TÚ", "ST", "RS", "SU"], "Cada par desciende una letra: XY → WX → VW → UV → TU."],
    "TPR2_18": ["¿Qué sigue? 40, 36, 32, 28, ?", "Los números disminuyen en una constante.", ["24", "25", "22", "20"], "Cada número disminuye en 4. Después de 28, el siguiente valor es 24."],
    "TPR2_19": ["¿Qué sigue? ○, ○○, ■, ■■, ○, ?", "A una forma simple le sigue su doble y luego la siguiente forma.", ["○○", "■", "○", "■■"], "El ciclo es: ○ simple, ○○ doble, ■ simple, ■■ doble, luego se repite. Después de ○ viene ○○."],
    "TPR2_20": ["Cuadrícula: 10, 20, 30/11, 22, 33/12, 24,?", "Cada fila multiplica el primer número por 1, 2 y 3.", ["36", "34", "38", "48"], "Fila 3: 12×1=12, 12×2=24, 12×3=36."],
    "TPR3_01": ["¿Qué sigue? 2, 3, 5, 8, 12, ?", "Observa las diferencias entre términos consecutivos: aumentan en 1.", ["17", "15", "16", "18"], "Las diferencias son 1, 2, 3, 4, por lo que la siguiente diferencia es 5: 12 + 5 = 17."],
    "TPR3_02": ["Cuadrícula: 3, 5, 15/4, 6, 24/7, 3,?", "¿Cómo se relacionan las dos primeras columnas con la tercera?", ["21", "10", "24", "30"], "Columna 1 × columna 2 = columna 3. Fila 3: 7 × 3 = 21."],
    "TPR3_03": ["¿Qué sigue? 49, 36, 25, 16, 9, ?", "Cada término es un cuadrado perfecto. ¿Qué cuadrados son?", ["4", "1", "6", "3"], "La cadena es 7², 6², 5², 4², 3², por lo que sigue 2² = 4."],
    "TPR3_04": ["¿Qué sigue? 20, 18, 15, 11, 6, ?", "La cantidad baja aumenta en 1 en cada paso.", ["0", "1", "2", "−1"], "Las diferencias son −2, −3, −4, −5, por lo que la siguiente es −6: 6 − 6 = 0."],
    "TPR3_05": ["Cuadrícula: 3, 9, 27/4, 16, 64/6, 36,?", "Cada fila usa potencias del primer número.", ["216", "180", "108", "72"], "El patrón de filas es n¹, n², n³. Fila 3: 6, 36, 216."],
    "TPR3_06": ["¿Qué sigue? 3, 5, 9, 15, 23, ?", "Calcule las diferencias: forme su propio patrón.", ["33", "31", "35", "29"], "Las diferencias son 2, 4, 6, 8, por lo que la siguiente es 10: 23 + 10 = 33."],
    "TPR3_07": ["Cuadrícula: 1, 5, 6/2, 8, 10/3, 11,?", "Agregue las dos primeras columnas de cada fila.", ["14", "13", "15", "33"], "Columna 1 + columna 2 = columna 3. Fila 3: 3 + 11 = 14."],
    "TPR3_08": ["¿Qué sigue? 1, 6, 15, 28, 45,?", "Mire las diferencias, luego las diferencias de esas diferencias.", ["66", "60", "56", "72"], "Las diferencias son 5, 9, 13, 17 (aumento en 4). La siguiente diferencia es 21: 45 + 21 = 66."],
    "TPR3_09": ["¿Qué sigue? 100, 95, 85, 70, 50,?", "¿Cuánto disminuye en cada paso? Esta cantidad está aumentando.", ["25", "30", "20", "35"], "Las diferencias son −5, −10, −15, −20, por lo que sigue −25: 50 − 25 = 25."],
    "TPR3_10": ["Cuadrícula: 3, 4, 12/5, 6, 30/7, 8,?", "¿Cómo se relaciona la columna 3 con las columnas 1 y 2?", ["56", "15", "48", "60"], "Columna 1 × columna 2 = columna 3. Fila 3: 7 × 8 = 56."],
    "TPR3_11": ["¿Qué sigue? 3, 8, 15, 24, 35,?", "Intenta expresar cada término como n² menos algo.", ["48", "44", "50", "42"], "Cada término es n² − 1: 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35, 7²−1=48."],
    "TPR3_12": ["Cuadrícula: 2, 10, 5/3, 18, 6/4, 28,?", "¿Cómo se relaciona la columna 3 con las otras columnas?", ["7", "8", "12", "32"], "Columna 2 ÷ columna 1 = columna 3. Fila 3: 28 ÷ 4 = 7."],
    "TPR3_13": ["¿Qué sigue? 5, 6, 8, 11, 15, 20,?", "Las diferencias entre los términos aumentan en 1 en cada paso.", ["26", "25", "27", "24"], "Las diferencias son 1, 2, 3, 4, 5, por lo que la siguiente es 6: 20 + 6 = 26."],
    "TPR3_14": ["¿Qué sigue? 2, 5, 10, 17, 26, ?", "Pruebe la fórmula n² + 1 para valores consecutivos de n.", ["37", "35", "38", "36"], "Cada término es n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TPR3_15": ["Cuadrícula: 2, 5, 7/3, 4, 7/8, 3,?", "Agregue las dos primeras columnas de cada fila.", ["11", "24", "5", "10"], "Columna 1 + columna 2 = columna 3. Fila 3: 8 + 3 = 11."],
    "TPR3_16": ["Cuadrícula: 6, 2, 3/15, 3, 5/24, 4,?", "Divida la columna 1 por la columna 2.", ["6", "8", "7", "28"], "Columna 1 ÷ columna 2 = columna 3. Fila 3: 24 ÷ 4 = 6."],
    "TPR3_17": ["¿Qué sigue? 2, 8, 32, 128,?", "Cada término se multiplica por el mismo número.", ["512", "256", "384", "640"], "Cada término se multiplica por 4. Después de 128, el siguiente término es 128 × 4 = 512."],
    "TPR3_18": ["¿Qué sigue? 10, 12, 16, 22, 30,?", "Vea cómo cambia el intervalo entre términos.", ["40", "38", "42", "36"], "Las diferencias son 2, 4, 6, 8, por lo que la siguiente es 10: 30 + 10 = 40."],
    "TPR3_19": ["¿Qué sigue? 4, 7, 12, 19, 28, ?", "Las diferencias entre los términos aumentan en 2 en cada paso.", ["39", "37", "41", "35"], "Las diferencias son 3, 5, 7, 9, por lo que la siguiente es 11: 28 + 11 = 39."],
    "TPR3_20": ["Cuadrícula: 4, 2, 8/9, 3, 27/16, 4,?", "La columna 1 es un cuadrado perfecto. ¿Cuáles son los valores del cubo?", ["64", "48", "32", "20"], "Columna 1 = n², columna 2 = n, columna 3 = n³. Fila 3: 4² = 16, 4, 4³ = 64."],
    "TPR4_01": ["¿Qué sigue? 1, 16, 81, 256,?", "Cada término es una cuarta potencia.", ["625", "512", "500", "1024"], "La cadena es 1⁴, 2⁴, 3⁴, 4⁴, por lo que sigue 5⁴ = 625."],
    "TPR4_02": ["Cuadrícula: 5, 25, 125/6, 36, 216/7, 49,?", "Cada fila muestra n, n², n³.", ["343", "294", "350", "336"], "Fila 3: 7¹ = 7, 7² = 49, 7³ = 343."],
    "TPR4_03": ["¿Qué sigue? 2, 8, 26, 80, 242,?", "Intenta expresar cada término como una potencia de 3 menos 1.", ["728", "486", "720", "500"], "Cada término es 3ⁿ − 1: 3¹−1=2, 3²−1=8, 3³−1=26, 3⁴−1=80, 3⁵−1=242, 3⁶−1=728."],
    "TPR4_04": ["¿Qué sigue? 1, 4, 13, 40, 121,?", "Cada término se triplica y luego aumenta en 1.", ["364", "242", "360", "400"], "Cada término = anterior × 3 + 1: 1→4, 4→13, 13→40, 40→121, 121→364."],
    "TPR4_05": ["¿Qué sigue? 2, 3, 5, 8, 13,?", "Mire las diferencias: sigue un patrón familiar.", ["21", "18", "20", "16"], "Las diferencias son 1, 2, 3, 5, 8; cada diferencia es la suma de las dos anteriores. La siguiente diferencia es 8, entonces 13 + 8 = 21."],
    "TPR4_06": ["¿Qué sigue? 1, 4, 10, 20, 35,?", "Observe las diferencias de segundo orden: aumentan en 1.", ["56", "50", "48", "55"], "Diferencias de primer orden: 3, 6, 10, 15. Diferencias de segundo orden: 3, 4, 5 → siguiente 6. Siguiente diferencia de primer orden: 21. Respuesta: 35 + 21 = 56."],
    "TPR4_07": ["¿Qué sigue? 1, 3, 2, 6, 4, 12, 8,?", "Divide la cadena en términos en posiciones impares y pares.", ["24", "16", "10", "20"], "Posiciones impares: 1, 2, 4, 8 (×2). Posiciones pares: 3, 6, 12, 24 (×2). El siguiente término par es 24."],
    "TPR4_08": ["Cuadrícula: 2, 3, 11/4, 5, 29/6, 7,?", "Pruebe (columna1 + 1) × (columna2 + 1) y ajuste.", ["55", "42", "48", "53"], "Columna 3 = (columna 1 + 1) × (columna 2 + 1) − 1. Fila 3: 7 × 8 − 1 = 55."],
    "TPR4_09": ["¿Qué sigue? 256, 128, 64, 32, 16,?", "Cada término se reduce a la mitad.", ["8", "4", "12", "10"], "Cada término es divisible por 2. Después de 16, el siguiente término es 16 ÷ 2 = 8."],
    "TPR4_10": ["Cuadrícula: 1, 2, 3, 6/2, 3, 5, 30/3, 4, 7,?", "¿Cómo se relaciona la última columna con las tres primeras?", ["84", "14", "21", "72"], "Columna 4 = columna 1 × columna 2 × columna 3. Fila 3: 3 × 4 × 7 = 84."],
    "TPR4_11": ["¿Qué sigue? 2, 6, 18, 54, ?", "Cada término se multiplica por el mismo número.", ["162", "108", "144", "216"], "Cada término se multiplica por 3. Después de 54, el siguiente término es 54 × 3 = 162."],
    "TPR4_12": ["¿Qué sigue? 1, 5, 14, 30, 55,?", "Las diferencias entre los términos son cuadrados perfectos.", ["91", "80", "85", "90"], "Las diferencias son 4, 9, 16, 25 (es decir, 2², 3², 4², 5²). La siguiente diferencia es 6² = 36: 55 + 36 = 91."],
    "TPR4_13": ["¿Qué sigue? 1000, 500, 250, 125,?", "Cada término se reduce a la mitad.", ["62,5", "60", "75", "100"], "Cada término es divisible por 2. Después de 125, el siguiente término es 125 ÷ 2 = 62,5."],
    "TPR4_14": ["Cuadrícula: 10, 3, 7/20, 8, 12/30, 11,?", "¿Cómo se relacionan aritméticamente las columnas?", ["19", "20", "21", "41"], "Columna 1 − columna 2 = columna 3. Fila 3: 30 − 11 = 19."],
    "TPR4_15": ["¿Qué sigue? 4, 5, 9, 14, 23, 37,?", "Cada término es la suma de los dos términos anteriores.", ["60", "51", "56", "74"], "Como ocurre con Fibonacci: cada término = la suma de los dos anteriores. 23 + 37 = 60."],
    "TPR4_16": ["Cuadrícula: 2, 8, 3/3, 27, 8/4, 64,?", "La columna 2 es una potencia de la columna 1. ¿Qué patrón sigue la columna 3?", ["15", "16", "12", "20"], "Columna 2 = columna 1³. Columna 3 = columna 1² − 1: 2²−1=3, 3²−1=8, 4²−1=15."],
    "TPR4_17": ["¿Qué sigue? 1, 5, 21, 85,?", "Intenta multiplicar cada término por 4 y sumar 1.", ["341", "256", "340", "345"], "Cada término = anterior × 4 + 1: 1→5, 5→21, 21→85, 85→341."],
    "TPR4_18": ["¿Qué sigue? 1, 2, 5, 12, 29, ?", "Cada término utiliza los dos anteriores con un multiplicador.", ["70", "58", "65", "72"], "Regla: a(n) = 2×a(n−1) + a(n−2). Comprueba: 2×2+1=5, 2×5+2=12, 2×12+5=29, 2×29+12=70."],
    "TPR4_19": ["Cuadrícula: 3, 2, 11/4, 3, 19/5, 4,?", "Intente elevar al cuadrado la columna 1 más la columna 2.", ["29", "20", "25", "30"], "Columna 3 = columna 1² + columna 2. Fila 3: 5² + 4 = 25 + 4 = 29."],
    "TPR4_20": ["Cuadrícula: 4, 3, 13/5, 2, 23/6, 1,?", "Pruebe al cuadrado la columna 1 menos la columna 2.", ["35", "30", "36", "42"], "Columna 3 = columna 1² − columna 2. Fila 3: 6² − 1 = 36 − 1 = 35."],
    "TPR5_01": ["¿Qué sigue en la secuencia de números primos? 23, 29, 31, 37, 41, ?", "Enumera los números primos después del 41.", ["43", "42", "45", "47"], "La cadena enumera números primos consecutivos. Después del 41, el siguiente número primo es el 43."],
    "TPR5_02": ["¿Qué sigue? 2, 1, 3, 4, 7, 11, 18,?", "Cada término es la suma de los dos términos anteriores.", ["29", "25", "27", "36"], "Serie de Lucas: cada término = la suma de los dos anteriores. 11 + 18 = 29."],
    "TPR5_03": ["Cuadrícula: 2, 8, 32/3, 27, 243/5, 125,?", "Cada columna usa una potencia impar del primer número.", ["3125", "625", "1250", "1500"], "El patrón de filas es n¹, n³, n⁵. Fila 3: 5¹=5, 5³=125, 5⁵=3125."],
    "TPR5_04": ["¿Qué sigue? 4, 6, 10, 14, 22, 26, ?", "Cada término es el doble de un número primo. ¿Qué primas?", ["34", "30", "32", "38"], "Cada término es 2 × un número primo consecutivo: 2×2=4, 2×3=6, 2×5=10, 2×7=14, 2×11=22, 2×13=26, 2×17=34."],
    "TPR5_05": ["¿Qué sigue? 0, 0, 1, 1, 2, 4, 7, 13,?", "Cada término es la suma de los tres términos anteriores.", ["24", "20", "26", "19"], "Es la serie de Tribonacci: cada término = la suma de los tres anteriores. 4 + 7 + 13 = 24."],
    "TPR5_06": ["¿Qué sigue? 2, 12, 36, 80, 150,?", "Intente expresar cada término como n²(n + 1).", ["252", "210", "240", "260"], "Cada término es n²(n+1): 1²×2=2, 2²×3=12, 3²×4=36, 4²×5=80, 5²×6=150, 6²×7=252."],
    "TPR5_07": ["Cuadrícula: 1, 2, 5/2, 3, 13/4, 5,?", "Pruebe con los cuadrados de las dos primeras columnas agregadas.", ["41", "20", "45", "36"], "Columna 3 = columna 1² + columna 2². Fila 3: 4² + 5² = 16 + 25 = 41."],
    "TPR5_08": ["¿Qué sigue? 2, 8, 18, 32, 50,?", "Intenta expresar cada término como 2n² para n consecutivos.", ["72", "60", "68", "80"], "Cada término es 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TPR5_09": ["¿Qué sigue? 2, 4, 16, 256,?", "Cada término es el cuadrado del término anterior.", ["65536", "512", "1024", "4096"], "Cada término = anterior². 2²=4, 4²=16, 16²=256, 256²=65536."],
    "TPR5_10": ["¿Qué sigue? 47, 43, 41, 37, 31, 29, ?", "Son números primos en orden descendente.", ["23", "27", "25", "19"], "La cadena enumera números primos consecutivos en orden descendente. Después del 29, el siguiente número primo más pequeño es el 23."],
    "TPR5_11": ["Cuadrícula: 2, 3, 7/4, 5, 21/6, 7,?", "Multiplica las dos primeras columnas y ajusta por 1.", ["43", "42", "44", "40"], "Columna 3 = columna 1 × columna 2 + 1. Fila 3: 6 × 7 + 1 = 43."],
    "TPR5_12": ["¿Qué sigue? 1, 5, 12, 22, 35,?", "Estos son números pentagonales: n(3n − 1)/2.", ["51", "48", "50", "55"], "Números pentagonales: n(3n−1)/2. Para n=6: 6×17/2 = 51."],
    "TPR5_13": ["¿Qué sigue? 2, 6, 30, 210,?", "Cada término se multiplica por el siguiente número primo.", ["2310", "1470", "1260", "1890"], "2×3=6, 6×5=30, 30×7=210, 210×11=2310. En cada paso multiplicas por el siguiente número primo."],
    "TPR5_14": ["Cuadrícula: 4, 16, 64/6, 36, 216/8, 64,?", "Cada fila muestra las potencias del primer número.", ["512", "256", "480", "128"], "El patrón de filas es n¹, n², n³. Fila 3: 8, 64, 512."],
    "TPR5_15": ["¿Qué sigue? 1, 3, 11, 43, ?", "Cada término se multiplica por 4 y se disminuye en 1.", ["171", "170", "172", "160"], "Cada término = anterior × 4 − 1: 1→3, 3→11, 11→43, 43→171."],
    "TPR5_16": ["¿Qué sigue? 59, 53, 47, 43, 41, 37,?", "Estos son números primos en orden descendente.", ["31", "33", "29", "35"], "La cadena enumera números primos consecutivos en orden inverso. Después de 37, el siguiente número primo más pequeño es 31."],
    "TPR5_17": ["¿Qué sigue? 27, 125, 343, 729,?", "Cada término es un cubo: ¿los números de quién?", ["1331", "1000", "1200", "1500"], "Son cubos de números impares consecutivos: 3³=27, 5³=125, 7³=343, 9³=729, 11³=1331."],
    "TPR5_18": ["Cuadrícula: 3, 2, 18/4, 3, 48/5, 4,?", "Intente elevar al cuadrado la columna1 multiplicada por la columna2.", ["100", "80", "60", "125"], "Columna 3 = columna 1² × columna 2. Fila 3: 5² × 4 = 25 × 4 = 100."],
    "TPR5_19": ["¿Qué sigue? 2, 3, 6, 7, 14, 15, ?", "La cadena alterna entre dos operaciones.", ["30", "16", "28", "22"], "El patrón alterna +1 y ×2: 2+1=3, 3×2=6, 6+1=7, 7×2=14, 14+1=15, 15×2=30."],
    "TPR5_20": ["¿Qué sigue? 1, 9, 36, 100, 225,?", "Cada término es un cuadrado perfecto. ¿A qué números se elevan?", ["441", "400", "484", "500"], "Estos son cuadrados de sumas acumuladas: (1)²=1, (1+2)²=9, (1+2+3)²=36, (1+2+3+4)²=100, (1+2+3+4+5)²=225, (1+2+3+4+5+6)²=441."],
    "TNR1_01": ["¿Qué sigue en la cadena: 7, 8, 9, 10, 11,?", "Mira la diferencia entre cada par de términos consecutivos.", ["12", "13", "10", "14"], "Cada término aumenta en 1. El siguiente término es 11 + 1 = 12."],
    "TNR1_02": ["¿Qué sigue en la cadena: 3, 5, 7, 9, 11,?", "Resta cada término del siguiente.", ["13", "12", "14", "15"], "Cada término aumenta en 2. El siguiente término es 11 + 2 = 13."],
    "TNR1_03": ["¿Qué sigue en la cadena: 10, 13, 16, 19, 22,?", "Encuentra la diferencia constante entre términos consecutivos.", ["25", "24", "26", "23"], "Cada término aumenta en 3. El siguiente término es 22 + 3 = 25."],
    "TNR1_04": ["¿Qué sigue en la cadena: 1, 5, 9, 13, 17,?", "¿Cuánto aumenta cada término con respecto al anterior?", ["21", "20", "22", "19"], "Cada término aumenta en 4. El siguiente término es 17 + 4 = 21."],
    "TNR1_05": ["¿Qué sigue en la cadena: 2, 7, 12, 17, 22,?", "Calcula el paso entre términos consecutivos.", ["27", "25", "28", "26"], "Cada término aumenta en 5. El siguiente término es 22 + 5 = 27."],
    "TNR1_06": ["¿Qué sigue en la cadena: 4, 10, 16, 22, 28,?", "¿Qué se agrega cada vez?", ["34", "32", "36", "30"], "Cada término aumenta en 6. El siguiente término es 28 + 6 = 34."],
    "TNR1_07": ["¿Qué sigue en la cadena: 3, 10, 17, 24, 31,?", "Encuentra la constante sumada a cada término.", ["38", "35", "39", "37"], "Cada término aumenta en 7. El siguiente término es 31 + 7 = 38."],
    "TNR1_08": ["¿Qué sigue en la cadena: 5, 13, 21, 29, 37,?", "Resta el primer término del segundo para encontrar el tamaño del paso.", ["45", "44", "46", "43"], "Cada término aumenta en 8. El siguiente término es 37 + 8 = 45."],
    "TNR1_09": ["¿Qué sigue en la cadena: 2, 11, 20, 29, 38,?", "¿Qué número se suma a cada paso?", ["47", "45", "48", "46"], "Cada término aumenta en 9. El siguiente término es 38 + 9 = 47."],
    "TNR1_10": ["¿Qué sigue en la cadena: 6, 16, 26, 36, 46,?", "Mire el intervalo entre dos términos consecutivos.", ["56", "54", "58", "52"], "Cada término aumenta en 10. El siguiente término es 46 + 10 = 56."],
    "TNR1_11": ["¿Qué sigue en la cadena: 20, 19, 18, 17, 16,?", "La cuerda disminuye. ¿Cuánto en cada paso?", ["15", "14", "17", "13"], "Cada término disminuye en 1. El siguiente término es 16 − 1 = 15."],
    "TNR1_12": ["¿Qué sigue en la cadena: 30, 28, 26, 24, 22,?", "Resta cada término del anterior.", ["20", "21", "18", "19"], "Cada término disminuye en 2. El siguiente término es 22 − 2 = 20."],
    "TNR1_13": ["¿Qué sigue en la cadena: 40, 37, 34, 31, 28,?", "La cuerda disminuye. Encuentra tu ritmo constante.", ["25", "26", "24", "27"], "Cada término disminuye en 3. El siguiente término es 28 − 3 = 25."],
    "TNR1_14": ["¿Qué sigue en la cadena: 50, 46, 42, 38, 34,?", "¿Cuánto disminuye cada vez?", ["30", "32", "28", "31"], "Cada término disminuye en 4. El siguiente término es 34 − 4 = 30."],
    "TNR1_15": ["¿Qué sigue en la cadena: 60, 55, 50, 45, 40,?", "Encuentra la medida más baja entre términos consecutivos.", ["35", "30", "38", "33"], "Cada término disminuye en 5. El siguiente término es 40 − 5 = 35."],
    "TNR1_16": ["¿Qué sigue en la cadena: 5, 16, 27, 38, 49,?", "Calcula la diferencia entre los dos primeros términos y comprueba si sigue siendo la misma.", ["60", "58", "61", "55"], "Cada término aumenta en 11. El siguiente término es 49 + 11 = 60."],
    "TNR1_17": ["¿Qué sigue en la cadena: 3, 15, 27, 39, 51,?", "¿Cuál es la constante que se agrega en cada paso?", ["63", "60", "64", "62"], "Cada término aumenta en 12. El siguiente término es 51 + 12 = 63."],
    "TNR1_18": ["¿Qué sigue en la cadena: 10, 25, 40, 55, 70,?", "Encuentra el tono fijo agregado entre los términos.", ["85", "80", "90", "75"], "Cada término aumenta en 15. El siguiente término es 70 + 15 = 85."],
    "TNR1_19": ["¿Qué sigue en la cadena: 5, 25, 45, 65, 85,?", "Calcula el tamaño del paso de cualquier término al siguiente.", ["105", "100", "110", "95"], "Cada término aumenta en 20. El siguiente término es 85 + 20 = 105."],
    "TNR1_20": ["¿Qué sigue en la cadena: 42, 36, 30, 24, 18,?", "La cuerda disminuye. ¿Qué se resta cada vez?", ["12", "14", "10", "16"], "Cada término disminuye en 6. El siguiente término es 18 − 6 = 12."],
    "TNR2_01": ["¿Qué sigue en la cadena: 5, 10, 20, 40, 80,?", "Intenta dividir cada término por el anterior.", ["160", "120", "140", "100"], "Cada término se multiplica por 2. El siguiente término es 80 × 2 = 160."],
    "TNR2_02": ["¿Qué sigue en la cadena: 2, 6, 18, 54, 162,?", "¿Cuál es la razón de términos consecutivos?", ["486", "324", "480", "648"], "Cada término se multiplica por 3. El siguiente término es 162 × 3 = 486."],
    "TNR2_03": ["¿Qué sigue en la cadena: 1, 4, 16, 64, 256,?", "Divide el segundo término por el primero para encontrar el multiplicador.", ["1024", "512", "768", "1280"], "Cada término se multiplica por 4. El siguiente término es 256 × 4 = 1024."],
    "TNR2_04": ["¿Qué sigue en la cadena: 2, 10, 50, 250, 1250,?", "Mira la proporción de términos consecutivos.", ["6250", "5000", "6000", "7500"], "Cada término se multiplica por 5. El siguiente término es 1250 × 5 = 6250."],
    "TNR2_05": ["¿Qué sigue en la cadena: 3, 30, 300, 3000, 30000,?", "Cada término recibe otro cero. ¿Por qué se multiplica?", ["300000", "60000", "200000", "330000"], "Cada término se multiplica por 10. El siguiente término es 30000 × 10 = 300000."],
    "TNR2_06": ["¿Qué sigue en la cadena: 640, 320, 160, 80, 40,?", "La cuerda se parte por la mitad. ¿Qué operación se aplica en cada paso?", ["20", "10", "30", "25"], "Cada término es divisible por 2. El siguiente término es 40 ÷ 2 = 20."],
    "TNR2_07": ["¿Qué sigue en la cadena: 729, 243, 81, 27, 9,?", "Intenta dividir cada término en el siguiente.", ["3", "6", "1", "4"], "Cada término es divisible por 3. El siguiente término es 9 ÷ 3 = 3."],
    "TNR2_08": ["¿Qué sigue en la cadena: 192, 96, 48, 24, 12,?", "¿Qué fracción del término anterior da el término actual?", ["6", "4", "8", "3"], "Cada término es divisible por 2. El siguiente término es 12 ÷ 2 = 6."],
    "TNR2_09": ["¿Qué sigue en la cadena: 3, 4, 7, 11, 18,?", "Intenta sumar dos términos consecutivos.", ["29", "25", "27", "30"], "Cada término es la suma de los dos anteriores: 11 + 18 = 29."],
    "TNR2_10": ["¿Qué sigue en la cadena: 2, 5, 7, 12, 19,?", "Observe cómo se relaciona cada término con los dos anteriores.", ["31", "26", "28", "33"], "Cada término es la suma de los dos anteriores: 12 + 19 = 31."],
    "TNR2_11": ["¿Qué sigue en la cadena: 4, 9, 19, 39, 79,?", "Intente duplicar un término y luego ajustarlo en un número pequeño.", ["159", "158", "160", "149"], "Cada término sigue la regla: anterior × 2 + 1. El siguiente término es 79 × 2 + 1 = 159."],
    "TNR2_12": ["¿Qué sigue en la cadena: 4, 12, 36, 108, 324,?", "Divide cada término por el término anterior para encontrar una razón constante.", ["972", "648", "1296", "900"], "Cada término se multiplica por 3. El siguiente término es 324 × 3 = 972."],
    "TNR2_13": ["¿Qué sigue en la cadena: 7, 14, 28, 56, 112,?", "¿Qué sucede cuando divides cada término por el término anterior?", ["224", "168", "220", "228"], "Cada término se multiplica por 2. El siguiente término es 112 × 2 = 224."],
    "TNR2_14": ["¿Qué sigue en la cadena: 1, 3, 4, 7, 11,?", "Comprueba si cada término es la suma de los dos anteriores.", ["18", "15", "16", "20"], "Cada término es la suma de los dos anteriores: 7 + 11 = 18."],
    "TNR2_15": ["¿Qué sigue en la cadena: 256, 128, 64, 32, 16,?", "Todas estas son potencias de 2. ¿Qué divisor conecta cada par?", ["8", "4", "12", "10"], "Cada término es divisible por 2. El siguiente término es 16 ÷ 2 = 8."],
    "TNR2_16": ["¿Qué sigue en la cadena: 1, 5, 25, 125, 625,?", "Encuentra el multiplicador dividiendo cualquier término por el término anterior.", ["3125", "1250", "3000", "3750"], "Cada término se multiplica por 5. El siguiente término es 625 × 5 = 3125."],
    "TNR2_17": ["¿Qué sigue en la cadena: 3, 8, 18, 38, 78,?", "Intente duplicar el término anterior y agregar una pequeña constante.", ["158", "156", "160", "148"], "Cada término sigue la regla: anterior × 2 + 2. El siguiente término es 78 × 2 + 2 = 158."],
    "TNR2_18": ["¿Qué sigue en la cadena: 1, 4, 5, 9, 14,?", "Observa si la suma de dos términos consecutivos da lo siguiente.", ["23", "19", "21", "25"], "Cada término es la suma de los dos anteriores: 9 + 14 = 23."],
    "TNR2_19": ["¿Qué sigue en la cadena: 2187, 729, 243, 81, 27,?", "Cada término es una fracción del anterior. ¿Qué divisor se utiliza?", ["9", "3", "18", "12"], "Cada término es divisible por 3. El siguiente término es 27 ÷ 3 = 9."],
    "TNR2_20": ["¿Qué sigue en la cadena: 2, 8, 32, 128, 512,?", "Divide términos consecutivos para encontrar el multiplicador constante.", ["2048", "1024", "2560", "1536"], "Cada término se multiplica por 4. El siguiente término es 512 × 4 = 2048."],
    "TNR3_01": ["¿Qué sigue en la cadena: 36, 49, 64, 81, 100,?", "Prueba la raíz cuadrada de cada término.", ["121", "110", "120", "125"], "Son cuadrados perfectos consecutivos: 6²=36, 7²=49, 8²=64, 9²=81, 10²=100, 11²=121."],
    "TNR3_02": ["¿Qué sigue en la cadena: 100, 121, 144, 169, 196,?", "Cada término es un cuadrado perfecto. ¿Qué cuadrados son estos?", ["225", "220", "230", "216"], "Son cuadrados perfectos consecutivos: 10²=100, 11²=121, 12²=144, 13²=169, 14²=196, 15²=225."],
    "TNR3_03": ["¿Qué sigue en la cadena: 125, 216, 343, 512, 729,?", "Prueba la raíz cúbica de cada término.", ["1000", "900", "1024", "972"], "Son cubos perfectos consecutivos: 5³=125, 6³=216, 7³=343, 8³=512, 9³=729, 10³=1000."],
    "TNR3_04": ["¿Qué sigue en la cadena: 343, 512, 729, 1000, 1331,?", "Son cubos de números enteros consecutivos. ¿Qué números enteros?", ["1728", "1500", "1700", "2000"], "Son cubos perfectos consecutivos: 7³=343, 8³=512, 9³=729, 10³=1000, 11³=1331, 12³=1728."],
    "TNR3_05": ["¿Qué sigue en la cadena: 10, 12, 16, 22, 30,?", "Calcula las diferencias entre los términos. ¿Estas diferencias forman un patrón?", ["40", "38", "42", "36"], "Las diferencias son 2, 4, 6, 8, aumentando en 2 en cada paso. La siguiente diferencia es 10, entonces 30 + 10 = 40."],
    "TNR3_06": ["¿Qué sigue en la cadena: 7, 10, 16, 25, 37,?", "Encuentra las diferencias entre los términos y luego busca un patrón en esas diferencias.", ["52", "49", "55", "46"], "Las diferencias son 3, 6, 9, 12, aumentando en 3 en cada paso. La siguiente diferencia es 15, entonces 37 + 15 = 52."],
    "TNR3_07": ["¿Qué sigue en la cadena: 5, 6, 9, 14, 21,?", "Las diferencias entre los términos son números impares consecutivos.", ["30", "28", "32", "27"], "Las diferencias son 1, 3, 5, 7: números impares consecutivos. La siguiente diferencia es 9, entonces 21 + 9 = 30."],
    "TNR3_08": ["¿Qué sigue en la cadena: 5, 7, 11, 13, 17,?", "Piensa en números que tienen exactamente dos divisores.", ["19", "18", "21", "20"], "Son números primos consecutivos que comienzan en 5. El siguiente número primo después de 17 es 19."],
    "TNR3_09": ["¿Qué sigue en la cadena: 11, 13, 17, 19, 23,?", "¿Estos números son divisibles sólo por 1 y por sí mismos?", ["29", "27", "25", "31"], "Son números primos consecutivos que comienzan en 11. El siguiente número primo después de 23 es 29."],
    "TNR3_10": ["¿Qué sigue en la cadena: 4, 16, 36, 64, 100,?", "Extrae la raíz cuadrada de cada término. ¿Qué tienen estos números en común?", ["144", "128", "136", "148"], "Estos son cuadrados de números pares consecutivos: 2²=4, 4²=16, 6²=36, 8²=64, 10²=100, 12²=144."],
    "TNR3_11": ["¿Qué sigue en la cadena: 1, 9, 25, 49, 81,?", "Extrae la raíz cuadrada de cada término. ¿Qué tipo de números son?", ["121", "100", "110", "125"], "Estos son cuadrados de números impares consecutivos: 1²=1, 3²=9, 5²=25, 7²=49, 9²=81, 11²=121."],
    "TNR3_12": ["¿Qué sigue en la cadena: 2, 5, 10, 17, 26,?", "Resta 1 de cada término. ¿Les suenan familiares los resultados?", ["37", "35", "36", "39"], "Cada término es n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TNR3_13": ["¿Qué sigue en la cadena: 0, 3, 8, 15, 24,?", "Suma 1 a cada término. ¿Qué cadena conocida obtienes?", ["35", "33", "36", "30"], "Cada término es n² − 1: 1²−1=0, 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35."],
    "TNR3_14": ["¿Qué sigue en la cadena: 5, 9, 17, 29, 45,?", "Calcule las diferencias y luego verifique si aumentan regularmente.", ["65", "61", "69", "57"], "Las diferencias son 4, 8, 12, 16, aumentando en 4 en cada paso. La siguiente diferencia es 20, entonces 45 + 20 = 65."],
    "TNR3_15": ["¿Qué sigue en la cadena: 2, 9, 28, 65, 126,?", "Resta 1 de cada término. ¿Qué tipo de números quedan?", ["217", "215", "220", "210"], "Cada término es n³ + 1: 1³+1=2, 2³+1=9, 3³+1=28, 4³+1=65, 5³+1=126, 6³+1=217."],
    "TNR3_16": ["¿Qué sigue en la cadena: 3, 8, 15, 24, 35,?", "Intenta expresar cada término como producto de dos números adyacentes.", ["48", "46", "50", "44"], "Cada término es n(n + 2): 1×3=3, 2×4=8, 3×5=15, 4×6=24, 5×7=35, 6×8=48."],
    "TNR3_17": ["¿Qué sigue en la cadena: 1, 5, 11, 19, 29,?", "Las diferencias entre los términos aumentan con una constante. Encuentra esa constante.", ["41", "39", "43", "37"], "Las diferencias son 4, 6, 8, 10, aumentando en 2 en cada paso. La siguiente diferencia es 12, entonces 29 + 12 = 41."],
    "TNR3_18": ["¿Qué sigue en la cadena: 2, 8, 18, 32, 50,?", "Intente dividir cada término entre 2. ¿Le suenan familiares los resultados?", ["72", "68", "74", "64"], "Cada término es 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TNR3_19": ["¿Qué sigue en la cadena: 4, 7, 12, 19, 28,?", "Resta 3 de cada término. ¿Qué cuerda reconoces?", ["39", "37", "41", "36"], "Cada término es n² + 3: 1²+3=4, 2²+3=7, 3²+3=12, 4²+3=19, 5²+3=28, 6²+3=39."],
    "TNR3_20": ["¿Qué sigue en la cadena: 4, 9, 19, 34, 54,?", "Encuentra las diferencias, luego las diferencias de esas diferencias.", ["79", "74", "84", "69"], "Las diferencias son 5, 10, 15, 20 (aumentando en 5 en cada paso). La siguiente diferencia es 25, entonces 54 + 25 = 79."],
    "TNR4_01": ["¿Qué sigue en la cadena: 2, 3, 7, 25, 121,?", "Resta 1 de cada término y comprueba si reconoces los números.", ["721", "720", "625", "719"], "Cada término es n! + 1: 1!+1=2, 2!+1=3, 3!+1=7, 4!+1=25, 5!+1=121, 6!+1=721."],
    "TNR4_02": ["¿Qué sigue en la cadena: 0, 1, 5, 23, 119,?", "Suma 1 a cada término. ¿Reconoces los números resultantes?", ["719", "720", "600", "721"], "Cada término es n! − 1: 1!−1=0, 2!−1=1, 3!−1=5, 4!−1=23, 5!−1=119, 6!−1=719."],
    "TNR4_03": ["¿Qué sigue en la cadena: 15, 21, 28, 36, 45,?", "Estos son números triangulares. Las diferencias entre los términos aumentan en 1 en cada paso.", ["55", "54", "56", "50"], "Números triangulares T(5)–T(10). Las diferencias son 6, 7, 8, 9, por lo que la siguiente es 10: 45 + 10 = 55."],
    "TNR4_04": ["¿Qué sigue en la cadena: 36, 45, 55, 66, 78,?", "Calcula las diferencias. Cada vez aumentan en 1: signo de los números triangulares.", ["91", "88", "90", "84"], "Números triangulares T(8)–T(13). Las diferencias son 9, 10, 11, 12, por lo que la siguiente es 13: 78 + 13 = 91."],
    "TNR4_05": ["¿Qué sigue en la cadena: 1, 5, 13, 29, 61,?", "Intente duplicar el término anterior y agregar una pequeña constante.", ["125", "122", "123", "127"], "Cada término sigue la regla: anterior × 2 + 3. El siguiente término es 61 × 2 + 3 = 125."],
    "TNR4_06": ["¿Qué sigue en la cadena: 1, 2, 5, 14, 41,?", "Intente multiplicar el término anterior por 3 y ajuste.", ["122", "120", "123", "82"], "Cada término sigue la regla: anterior × 3 − 1. El siguiente término es 41 × 3 − 1 = 122."],
    "TNR4_07": ["¿Qué sigue en la cadena: 2, 9, 23, 51, 107,?", "Duplique el término anterior y agregue una constante para obtener el siguiente.", ["219", "214", "215", "221"], "Cada término sigue la regla: anterior × 2 + 5. El siguiente término es 107 × 2 + 5 = 219."],
    "TNR4_08": ["¿Qué sigue en la cadena: 9, 25, 49, 121, 169,?", "Saca la raíz cuadrada de cada término y luego piensa en lo que tienen de especial estos números.", ["289", "225", "256", "324"], "Estos son cuadrados de números primos consecutivos: 3²=9, 5²=25, 7²=49, 11²=121, 13²=169, 17²=289."],
    "TNR4_09": ["¿Qué sigue en la cadena: 10, 11, 15, 24, 40,?", "Encuentra las diferencias entre los términos. ¿Son estas diferencias una cadena conocida?", ["65", "56", "64", "60"], "Las diferencias son 1, 4, 9, 16: cuadrados perfectos (1², 2², 3², 4²). La siguiente diferencia es 5²=25, entonces 40 + 25 = 65."],
    "TNR4_10": ["¿Qué sigue en la cadena: 0, 1, 3, 9, 33,?", "Calcula las diferencias entre los términos. ¿Te recuerdan a una frase famosa?", ["153", "129", "150", "57"], "Las diferencias son 1, 2, 6, 24, es decir, factoriales (1!, 2!, 3!, 4!). La siguiente diferencia es 5!=120, entonces 33 + 120 = 153."],
    "TNR4_11": ["¿Qué sigue en la cadena: 2, 7, 22, 67, 202,?", "Multiplica el término anterior por un número y suma una constante.", ["607", "606", "605", "610"], "Cada término sigue la regla: anterior × 3 + 1. El siguiente término es 202 × 3 + 1 = 607."],
    "TNR4_12": ["¿Qué sigue en la cadena: 20, 37, 71, 139, 275,?", "Intenta duplicar el término anterior y restar una pequeña constante.", ["547", "550", "545", "553"], "Cada término sigue la regla: anterior × 2 − 3. El siguiente término es 275 × 2 − 3 = 547."],
    "TNR4_13": ["¿Qué sigue en la cadena: 1, 5, 14, 30, 55,?", "Las diferencias entre los términos son cuadrados perfectos. Agrega cuadrados consecutivos.", ["91", "85", "90", "80"], "Estas son sumas acumulativas de cuadrados: 1, 1+4=5, 5+9=14, 14+16=30, 30+25=55, 55+36=91."],
    "TNR4_14": ["¿Qué sigue en la cadena: 2, 4, 12, 48, 240,?", "Intente dividir cada término entre 2. ¿Los resultados parecen factoriales?", ["1440", "1200", "1680", "960"], "Cada término es 2 × n!: 2×1!=2, 2×2!=4, 2×3!=12, 2×4!=48, 2×5!=240, 2×6!=1440."],
    "TNR4_15": ["¿Qué sigue en la cadena: 6, 13, 27, 55, 111,?", "Duplique el término anterior y agregue una constante en cada paso.", ["223", "222", "220", "225"], "Cada término sigue la regla: anterior × 2 + 1. El siguiente término es 111 × 2 + 1 = 223."],
    "TNR4_16": ["¿Qué sigue en la cadena: 10, 11, 14, 20, 30,?", "Las diferencias entre los términos son números triangulares: 1, 3, 6, 10,…", ["45", "40", "42", "50"], "Las diferencias son 1, 3, 6, 10: números triangulares. El siguiente número triangular es 15, entonces 30 + 15 = 45."],
    "TNR4_17": ["¿Qué sigue en la cadena: 12, 20, 30, 42, 56,?", "Intenta expresar cada término como producto de dos números enteros consecutivos.", ["72", "68", "70", "64"], "Estos son n(n+1) números oblongos: 3×4=12, 4×5=20, 5×6=30, 6×7=42, 7×8=56, 8×9=72."],
    "TNR4_18": ["¿Qué sigue en la cadena: 1, 9, 36, 100, 225,?", "Cada término es el cuadrado de un número triangular o, equivalentemente, la suma cúbica acumulada.", ["441", "400", "440", "450"], "Estas son sumas de cubos consecutivos: 1³=1, 1+8=9, 9+27=36, 36+64=100, 100+125=225, 225+216=441."],
    "TNR4_19": ["¿Qué sigue en la cadena: 3, 7, 19, 55, 163,?", "Multiplica el término anterior por un número y resta una constante.", ["487", "489", "485", "492"], "Cada término sigue la regla: anterior × 3 − 2. El siguiente término es 163 × 3 − 2 = 487."],
    "TNR4_20": ["¿Qué sigue en la cadena: 12, 23, 45, 89, 177,?", "Duplica el término anterior y haz un pequeño ajuste.", ["353", "354", "355", "350"], "Cada término sigue la regla: anterior × 2 − 1. El siguiente término es 177 × 2 − 1 = 353."],
    "TNR5_01": ["¿Qué sigue en la cadena: 1, 2, 9, 64, 625,?", "Piense en cuánta potencia se eleva la base desde cada posición.", ["7776", "7774", "7200", "3125"], "Cada término es n elevado a la potencia (n−1): 1⁰=1, 2¹=2, 3²=9, 4³=64, 5⁴=625, 6⁵=7776."],
    "TNR5_02": ["¿Qué sigue en la cadena: 2, 10, 30, 68, 130,?", "Intenta dividir cada término en una parte cúbica y una parte lineal.", ["222", "220", "218", "216"], "Cada término es n³ + n: 1+1=2, 8+2=10, 27+3=30, 64+4=68, 125+5=130, 216+6=222."],
    "TNR5_03": ["¿Qué sigue en la cadena: 1, 1, 2, 5, 14,?", "Estos son los números catalanes. Cada C(n) = C(0)C(n−1) + C(1)C(n−2) +… + C(n−1)C(0).", ["42", "28", "35", "48"], "Números catalanes: C(0)=1, C(1)=1, C(2)=2, C(3)=5, C(4)=14, C(5)=42."],
    "TNR5_04": ["¿Qué sigue en la cadena: 1, 5, 12, 22, 35,?", "Las diferencias son 4, 7, 10, 13: progresión aritmética hasta el paso 3.", ["51", "48", "50", "55"], "Estos son números pentagonales: n(3n−1)/2. Para n=6: 6×17/2 = 51."],
    "TNR5_05": ["¿Qué sigue en la cadena: 2, 5, 13, 35, 97,?", "Intenta expresar cada término como una suma de dos exponenciales.", ["275", "265", "270", "280"], "Cada término es 2ⁿ + 3ⁿ (comenzando en n=0): 1+1=2, 2+3=5, 4+9=13, 8+27=35, 16+81=97, 32+243=275."],
    "TNR5_06": ["¿Qué sigue en la cadena: 1, 5, 17, 53, 161,?", "Multiplica el término anterior por 3 y suma una pequeña constante.", ["485", "483", "322", "487"], "Cada término sigue la regla: anterior × 3 + 2. El siguiente término es 161 × 3 + 2 = 485."],
    "TNR5_07": ["¿Qué sigue en la cadena: 1, 2, 5, 12, 27,?", "Piensa en potencias de 2, luego resta algo que dependa de la posición.", ["58", "54", "56", "60"], "Cada término es 2ⁿ − n: 2¹−1=1, 2²−2=2, 2³−3=5, 2⁴−4=12, 2⁵−5=27, 2⁶−6=58."],
    "TNR5_08": ["¿Qué sigue en la cadena: 2, 12, 36, 80, 150,?", "Intenta factorizar cada término como n² multiplicado por algo.", ["252", "240", "250", "260"], "Cada término es n²(n+1): 1×2=2, 4×3=12, 9×4=36, 16×5=80, 25×6=150, 36×7=252."],
    "TNR5_09": ["¿Qué sigue en la cadena: 1, 6, 15, 28, 45,?", "Las diferencias son 5, 9, 13, 17; aumentan en 4. Estos son números hexadecimales.", ["66", "60", "63", "70"], "Números hexagonales: n(2n−1). Para n=6: 6×11 = 66."],
    "TNR5_10": ["¿Qué sigue en la cadena: 2, 6, 15, 40, 145,?", "Intenta dividir cada término en una parte factorial y una cuadrática.", ["756", "750", "745", "760"], "Cada término es n! + n²: 1!+1=2, 2!+4=6, 3!+9=15, 4!+16=40, 5!+25=145, 6!+36=756."],
    "TNR5_11": ["¿Qué sigue en la cadena: 2, 4, 7, 14, 17,?", "Las operaciones alternan entre dos reglas diferentes en pasos pares e impares.", ["34", "20", "31", "37"], "El patrón se alterna: ×2, +3, ×2, +3, ×2. Entonces 17 × 2 = 34."],
    "TNR5_12": ["¿Qué sigue en la cadena: 1, 5, 19, 65, 211,?", "Expresa cada término como la diferencia de dos exponenciales.", ["665", "660", "633", "670"], "Cada término es 3ⁿ − 2ⁿ: 3−2=1, 9−4=5, 27−8=19, 81−16=65, 243−32=211, 729−64=665."],
    "TNR5_13": ["¿Qué sigue en la cadena: 1, 4, 11, 29, 76,?", "Cada término depende de los dos anteriores. Prueba una combinación lineal.", ["199", "197", "200", "228"], "La regla es a(n) = 3×a(n−1) − a(n−2): 3×29−11=76, 3×76−29=199."],
    "TNR5_14": ["¿Qué sigue en la cadena: 20, 22, 26, 34, 50,?", "Las diferencias son 2, 4, 8, 16: potencias de 2.", ["82", "66", "80", "84"], "Las diferencias son potencias de 2: 2, 4, 8, 16. La siguiente diferencia es 32, entonces 50 + 32 = 82."],
    "TNR5_15": ["¿Qué sigue en la cadena: 1, 4, 10, 20, 35,?", "Estos son números tetraédricos: sumas de números triangulares consecutivos.", ["56", "50", "55", "60"], "Números tetraédricos: n(n+1)(n+2)/6. Para n=6: 6×7×8/6 = 56."],
    "TNR5_16": ["¿Qué sigue en la cadena: 1, 13, 37, 73, 121,?", "Las diferencias son 12, 24, 36, 48: múltiplos de 12.", ["181", "169", "175", "193"], "Estos son números de estrellas: 6n(n−1)+1. Para n=6: 6×30+1 = 181."],
    "TNR5_17": ["¿Qué sigue en la cadena: 1, 7, 19, 37, 61,?", "Las diferencias son 6, 12, 18, 24: múltiplos de 6.", ["91", "85", "90", "97"], "Estos son números hexagonales centrados: 3n(n−1)+1. Para n=6: 3×30+1 = 91."],
    "TNR5_18": ["¿Qué sigue en la cadena: 3, 8, 17, 32, 57,?", "Intenta expresar cada término como la suma de un cuadrado y una potencia de 2.", ["100", "96", "98", "105"], "Cada término es n² + 2ⁿ: 1+2=3, 4+4=8, 9+8=17, 16+16=32, 25+32=57, 36+64=100."],
    "TNR5_19": ["¿Qué sigue en la cadena: 1, 4, 8, 11, 22,?", "Se alternan dos operaciones diferentes. Uno suma, el otro multiplica.", ["25", "44", "24", "26"], "El patrón se alterna: +3, ×2, +3, ×2, +3. Entonces 22 + 3 = 25."],
    "TNR5_20": ["¿Qué sigue en la cadena: 1, 1, 3, 5, 11,?", "Cada término utiliza los dos términos anteriores con pesos diferentes.", ["21", "16", "22", "19"], "La regla es a(n) = a(n−1) + 2×a(n−2): 5 + 2×3 = 11, 11 + 2×5 = 21."],
    "TLR1_01": ["Todos los médicos son profesionales. El Dr. Adams es médico. ¿Qué conclusión puedes sacar?", "Si todos los X son Y y Z es X, entonces Z es Y.", ["El Dr. Adams es profesional.", "El Dr. Adams no es un profesional.", "Algunos profesionales no son médicos.", "Todos los profesionales son médicos."], "Todos los médicos son profesionales y el Dr. Adams es médico, por lo que el Dr. Adams es un profesional. Este es un silogismo afirmativo universal directo."],
    "TLR1_02": ["Todos los leones son animales. Simba es un león. ¿Qué conclusión puedes sacar?", "Si todos los miembros del grupo X pertenecen al grupo Y, y Simba está en X...", ["simba es un animal", "Todos los animales son leones.", "simba no es un animal", "Algunos animales no son leones"], "Todos los leones son animales, Simba es un león, entonces Simba es un animal."],
    "TLR1_03": ["Todas las naranjas son frutas. Este objeto es una naranja. ¿Qué conclusión puedes sacar?", "Si alguna naranja es una fruta, y este objeto es una naranja...", ["Este objeto es fruta.", "Todas las frutas son naranjas.", "Este objeto es vegetal.", "Este artículo puede no ser fruta."], "Todas las naranjas son frutas, este objeto es una naranja, entonces es una fruta."],
    "TLR1_04": ["Todos los coches son vehículos. Un BMW es un coche. ¿Qué conclusión puedes sacar?", "Los automóviles son un subconjunto de vehículos. ¿Dónde encaja BMW?", ["El BMW es un vehículo.", "Todos los vehículos son coches.", "El BMW no es un vehículo", "Algunos vehículos no son automóviles."], "Todos los coches son vehículos, BMW es coche, por tanto BMW es vehículo."],
    "TLR1_05": ["Ningún pájaro es insecto. Un mirlo es un pájaro. ¿Qué conclusión puedes sacar?", "Si ningún X es Y, y el mirlo es X…", ["Un mirlo no es un insecto", "Un mirlo es un insecto", "Algunos insectos son pájaros", "Todos los mirlos son insectos"], "Ningún pájaro es insecto; como el mirlo es pájaro, no puede ser insecto."],
    "TLR1_06": ["Cualquier hielo está frío. El cubo que hay sobre la mesa está hecho de hielo. ¿Qué conclusión puedes sacar?", "Si todo lo que es hielo está frío, y el cubo es hielo…", ["el cubo esta frio", "El cubo esta caliente", "No todo el hielo está frío", "la mesa esta fria"], "Cualquier hielo está frío, el cubo es hielo, entonces el cubo está frío."],
    "TLR1_07": ["Todos los violines son instrumentos musicales. Un Stradivarius es un violín. ¿Qué conclusión puedes sacar?", "Los violines forman parte de la multitud de instrumentos. Stradivarius es...", ["Stradivarius es un instrumento", "Todos los instrumentos son violines.", "Stradivarius no es un instrumento", "Algunos instrumentos no se pueden tocar."], "Todos los violines son instrumentos, el Stradivarius es un violín, entonces el Stradivarius es un instrumento."],
    "TLR1_08": ["Todas las rosas son plantas. Este ejemplar es rosa. ¿Qué conclusión puedes sacar?", "Las rosas son un subconjunto de plantas. El ejemplar es rosa, así que…", ["El ejemplar es una planta.", "Todas las plantas son rosas.", "El ejemplar no es una planta.", "Las rosas no son plantas."], "Todas las rosas son plantas, este ejemplar es una rosa, por lo tanto es una planta."],
    "TLR1_09": ["Todo el oro es metálico. Este anillo está hecho de oro. ¿Qué conclusión puedes sacar?", "El oro siempre es metálico. El anillo es de oro, así que...", ["el anillo es metalico", "Todos los cuerpos metálicos son dorados.", "El anillo no es metal.", "El oro a veces no es metálico"], "Todo el oro es metálico, el anillo está hecho de oro, entonces el anillo es metálico."],
    "TLR1_10": ["Todos los ríos contienen agua corriente. El Amazonas es un río. ¿Qué conclusión puedes sacar?", "Si todo río tiene agua corriente y el Amazonas es un río...", ["El Amazonas contiene agua corriente.", "Toda agua que fluye es río.", "El Amazonas no tiene agua.", "Algunos ríos están secos"], "Todos los ríos contienen agua que fluye, el Amazonas es un río, por lo que contiene agua que fluye."],
    "TLR1_11": ["Todas las novelas son libros. Todos los libros tienen páginas. ¿Qué conclusión puedes sacar?", "Conecte las relaciones: novelas → libros → páginas.", ["Todas las novelas tienen páginas.", "Todas las páginas están solo en rumano.", "Algunos libros no son novelas.", "Las novelas no tienen páginas."], "Todas las novelas son libros, todos los libros tienen páginas, por lo que por transitividad todas las novelas tienen páginas."],
    "TLR1_12": ["Todos los chefs saben cocinar. Pierre es cocinero. ¿Qué conclusión puedes sacar?", "Si todo chef sabe cocinar y Pierre es chef…", ["Pedro sabe cocinar", "Cualquiera que sepa cocinar es chef.", "Pierre no sabe cocinar", "Algunos chefs no saben cocinar"], "Todos los chefs saben cocinar, Pierre es chef, entonces Pierre sabe cocinar."],
    "TLR1_13": ["Todas las águilas son pájaros. Todas las aves tienen plumas. ¿Qué conclusión puedes sacar?", "Conecte las multitudes: águilas ⊂ pájaros ⊂ criaturas emplumadas.", ["Todas las águilas tienen plumas.", "Todas las criaturas voladoras son águilas.", "Las águilas no tienen plumas.", "Algunas aves no son águilas"], "Todas las águilas son pájaros, todos los pájaros tienen plumas, por lo tanto todas las águilas tienen plumas."],
    "TLR1_14": ["Todos los planetas orbitan alrededor de una estrella. Saturno es un planeta. ¿Qué conclusión puedes sacar?", "Los planetas orbitan alrededor de estrellas. Saturno es un planeta, entonces...", ["Saturno orbita una estrella", "Todo lo que orbita alrededor de una estrella es un planeta.", "Saturno no orbita una estrella", "La estrella orbita alrededor de Saturno."], "Todos los planetas orbitan alrededor de una estrella, Saturno es un planeta, por lo que Saturno orbita alrededor de una estrella."],
    "TLR1_15": ["Todas las ballenas son mamíferos. La ballena azul es una ballena. ¿Qué conclusión puedes sacar?", "Las ballenas son un subconjunto de mamíferos. La ballena azul es una ballena, entonces...", ["La ballena azul es un mamífero.", "Todos los mamíferos son ballenas.", "La ballena azul es un pez.", "Algunas ballenas no son mamíferos."], "Todas las ballenas son mamíferos, la ballena azul es una ballena, por lo que es un mamífero."],
    "TLR1_16": ["Ningún herbívoro come carne. El conejo es un herbívoro. ¿Qué conclusión puedes sacar?", "Si ningún herbívoro come carne y el conejo es herbívoro…", ["El conejo no come carne.", "El conejo come carne.", "Algunos herbívoros comen carne.", "Todos los carnívoros son conejos."], "Los herbívoros no comen carne, el conejo es herbívoro, por lo tanto no come carne."],
    "TLR1_17": ["Todos los cachorros son perros. Todos los perros son cánidos. ¿Qué conclusión puedes sacar?", "Cadena: cachorros ⊂ perros ⊂ cánidos.", ["Todos los cachorros son cánidos.", "Todos los cánidos son cachorros.", "Los cachorros no son caninos.", "Algunos perros no son cánidos"], "Todos los cachorros son perros, todos los perros son cánidos, por lo tanto todos los cachorros son cánidos."],
    "TLR1_18": ["Todos los profesores trabajan en educación. El señor Brown es profesor. ¿Qué conclusión puedes sacar?", "Si todos los profesores trabajan en educación y el señor Brown es profesor...", ["El Sr. Brown trabaja en educación.", "Todo el mundo en la educación es un maestro.", "El señor Brown no trabaja en educación.", "Algunos profesores no trabajan en educación."], "Todos los profesores trabajan en educación, el Sr. Brown es profesor, por lo que trabaja en educación."],
    "TLR1_19": ["Todos los diamantes son piedras preciosas. Todas las gemas son valiosas. ¿Qué conclusión puedes sacar?", "Cadena: Diamantes ⊂ Gemas ⊂ Objetos de valor.", ["Todos los diamantes son valiosos", "Todas las cosas valiosas son diamantes.", "Los diamantes no tienen valor", "Algunas gemas no valen nada"], "Todos los diamantes son piedras preciosas, son valiosos, por lo tanto todos los diamantes son valiosos."],
    "TLR1_20": ["Todos los días de verano son calurosos. Hoy es un día de verano. ¿Qué conclusión puedes sacar?", "Si todos los días de verano son calurosos y hoy es un día de verano…", ["hoy hace calor", "Todos los días cálidos son verano.", "hace frio hoy", "Los días de verano no siempre son calurosos"], "Todos los días de verano son calurosos, hoy es un día de verano, por eso hoy hace calor."],
    "TLR2_01": ["Si nieva, la temperatura es bajo cero. Nieve. ¿Qué conclusión puedes sacar?", "Modus ponens: si P→Q y P es verdadero, entonces Q es verdadero.", ["La temperatura está bajo cero.", "La temperatura está por encima del punto de congelación.", "no esta nevando", "No se puede sacar ninguna conclusión"], "Modus ponens: P→Q (nieve → bajo cero). P es verdadera, entonces Q es verdadera."],
    "TLR2_02": ["Si estudias regularmente, tus notas mejoran. Tus calificaciones no han mejorado. ¿Qué conclusión puedes sacar?", "Modus tollens: si P→Q y Q es falso, entonces P es falso.", ["No estudiaste regularmente", "Estudiaste regularmente", "Calificaciones mejoradas", "El aprendizaje no influye en las calificaciones."], "Modus tollens: P→Q (aprendizaje → mejores notas). Q es falso, entonces P es falso."],
    "TLR2_03": ["Si el teléfono está completamente cargado, dura todo el día. Tu teléfono está completamente cargado. ¿Qué conclusión puedes sacar?", "El antecedente es verdadero: se aplica el modus ponens.", ["El teléfono durará todo el día.", "El teléfono no durará todo el día.", "El teléfono no está cargado", "No se puede sacar ninguna conclusión"], "Modus ponens: P→Q (cargado → mantener el día). P es verdadera, entonces Q es verdadera."],
    "TLR2_04": ["Si la alarma está puesta, suena a las 7 am. La alarma no sonó a las 7. ¿Qué conclusión puedes sacar?", "El consecuente es falso: se aplica el modus tollens.", ["La alarma no fue puesta", "La alarma fue puesta", "La alarma sonó a las 7", "La alarma esta rota"], "Modus tollens: P→Q (colgar → anillo). Q es falso, entonces P es falso."],
    "TLR2_05": ["Si tienes la llave correcta, se abre la cerradura. Tienes la llave correcta. ¿Qué conclusión sacas?", "Se cumple el antecedente: modus ponens.", ["La cerradura se abre", "La cerradura no se abre", "No tienes la llave correcta", "La cerradura está bloqueada"], "Modus ponens: P→Q (llave correcta → se abre). P es verdadera, luego Q es verdadera."],
    "TLR2_06": ["Si hay energía, el refrigerador funciona. La nevera no funciona. ¿Qué conclusión puedes sacar?", "El consecuente es falso: se aplica el modus tollens.", ["La corriente no está encendida.", "La corriente esta encendida", "La nevera esta funcionando", "No se puede sacar ninguna conclusión"], "Modus tollens: P→Q (actual → en marcha). Q es falso, entonces P es falso."],
    "TLR2_07": ["Si riegas las plantas a diario, se mantienen verdes. Úselos a diario. ¿Qué conclusión puedes sacar?", "Se cumple la condición: ¿qué sigue?", ["Tus plantas se mantienen verdes", "las plantas se marchitan", "No los uses", "El riego no tiene ningún efecto."], "Modus ponens: P→Q (riego diario → verduras). P es verdadera, entonces Q es verdadera."],
    "TLR2_08": ["Si el coche tiene combustible, el motor puede arrancar. El motor no arranca. ¿Qué conclusión puedes sacar?", "El resultado no se produjo: aplicar el modus tollens.", ["El auto no tiene combustible.", "el auto tiene combustible", "El motor arrancó", "No se puede sacar ninguna conclusión"], "Modus peajes: P→Q (combustible → arranque). Q es falso, entonces P es falso."],
    "TLR2_09": ["Si compras un billete, podrás subir al tren. Compraste un boleto. ¿Qué conclusión puedes sacar?", "Has cumplido la condición: ¿qué sigue?", ["Puedes subir al tren.", "no puedes subir al tren", "No compraste un boleto", "El tren esta cancelado"], "Modus ponens: P→Q (billete → subidas). P es verdadera, entonces Q es verdadera."],
    "TLR2_10": ["Si tienes un pasaporte válido, puedes cruzar la frontera. No puedes cruzar la frontera. ¿Qué conclusión puedes sacar?", "Si P→Q y Q es falso, ¿qué significa para P?", ["No tienes un pasaporte válido", "Tienes un pasaporte válido", "Cruzaste la frontera", "No se necesita pasaporte"], "Modus tollens: P→Q (pasaporte → pase). Q es falso, entonces P es falso."],
    "TLR2_11": ["Si un animal es un caballo, tiene cuatro patas. Este animal tiene cuatro patas. ¿Qué conclusión puedes sacar?", "La verdad del consecuente no prueba el antecedente. Muchos animales tienen cuatro patas.", ["No podemos concluir que sea un caballo.", "Definitivamente es un caballo", "tiene dos patas", "no es un animal"], "Falacia de afirmar el consecuente: P→Q y Q no dan como resultado P. Muchos animales que no son caballos tienen cuatro patas."],
    "TLR2_12": ["Si alguien es abogado, estudió derecho. Sam estudió derecho. ¿Qué conclusión puedes sacar?", "Sólo porque Q sea verdadera, no se sigue que P sea verdadera.", ["No podemos concluir que Sam sea abogado.", "Sam definitivamente es un abogado.", "Sam no estudió derecho", "Todos los que han estudiado derecho son abogados."], "Enunciado del consecuente: De P→Q (abogado → estudió derecho) y Q no se sigue que Sam sea abogado."],
    "TLR2_13": ["Si el horno está encendido, la cocina se calienta. La cocina no hace calor. ¿Qué conclusión puedes sacar?", "La consecuencia es falsa: modus tollens.", ["El horno no está encendido.", "el horno esta encendido", "La cocina esta calientita", "No se puede sacar ninguna conclusión"], "Modus tollens: P→Q (horno → caliente). Q es falso, entonces P es falso."],
    "TLR2_14": ["Si pisas el freno, el coche frena. Pisaste el freno. ¿Qué conclusión puedes sacar?", "El antecedente es verdadero: modus ponens.", ["El auto frena", "el auto acelera", "No pisaste el freno", "No pasa nada"], "Modus ponens: P→Q (frenar → desacelerar). P es verdadera, entonces Q es verdadera."],
    "TLR2_15": ["Si nieva, el cielo está nublado. El cielo se está cubriendo de nubes. ¿Qué conclusión puedes sacar?", "Los cielos nublados pueden no tener nieve. ¿Es coherente la afirmación?", ["No podemos concluir que está nevando.", "Por supuesto que está nevando", "el cielo esta claro", "Nunca nieva cuando está nublado"], "Enunciado del consecuente: P→Q y Q no dan como resultado P."],
    "TLR2_16": ["Si la batería está cargada, la linterna funciona. La linterna no funciona. ¿Qué conclusión puedes sacar?", "Q es falsa: ¿qué dice eso sobre P?", ["La batería no está cargada", "La bateria esta cargada", "La linterna funciona", "No se puede sacar ninguna conclusión"], "Modus tollens: P→Q (cargado → trabajando). Q es falso, entonces P es falso."],
    "TLR2_17": ["Si le pones azúcar al té, el té se vuelve dulce. Le pones azúcar al té. ¿Qué conclusión puedes sacar?", "Se cumple la condición: modus ponens.", ["El té se vuelve dulce.", "El té sigue amargo.", "No agregaste azúcar", "El azúcar no tiene ningún efecto."], "Modus ponens: P→Q (azúcar → dulce). P es verdadera, entonces Q es verdadera."],
    "TLR2_18": ["Si el enrutador Wi-Fi está encendido, los dispositivos pueden conectarse a Internet. Los dispositivos no se pueden conectar. ¿Qué conclusión puedes sacar?", "Q es falsa: modus tollens.", ["El enrutador Wi-Fi no está encendido", "El enrutador Wi-Fi está encendido", "Los dispositivos pueden conectarse", "internet no existe"], "Modus peaje: P→Q (encendido → conectar). Q es falso, entonces P es falso."],
    "TLR2_19": ["Si un estudiante se registra en el curso, recibe el programa de estudios. Emma se matriculó en el curso. ¿Qué conclusión puedes sacar?", "Emma ha cumplido la condición: ¿qué sigue?", ["Emma recibe el plan de estudios.", "Emma no entiende el plan de estudios.", "Emma no se registró", "El curso no tiene horario."], "Modus ponens: P→Q (escrito → programa). P es verdadera para Emma, ​​​​por lo que Q es verdadera."],
    "TLR2_20": ["Si es domingo, la tienda está cerrada. No es domingo. ¿Qué conclusión puedes sacar?", "El antecedente es falso; no indica si Q es verdadero (negación del antecedente).", ["No podemos concluir si la tienda está abierta o cerrada.", "La tienda definitivamente está abierta.", "La tienda definitivamente está cerrada.", "debe ser el sabado"], "Negar el antecedente es un error: no se sigue nada seguro acerca de Q de P→Q y de P falso."],
    "TLR3_01": ["Anna es más alta que Dana. Dana es más alta que Ben. Ben es más alto que Carl. ¿Quién es el más bajo?", "Escribe la cadena de desigualdades y encuentra la \"base\".", ["carlos", "ben", "Dana", "ana"], "Anna > Dana > Ben > Carl. Carl es bajo, por eso el más bajo."],
    "TLR3_02": ["Felix es más ligero que George. Harry pesa más que George. Iván es más ligero que Félix. ¿Quién es el más difícil?", "Orden: Harry > George > Félix > Iván.", ["harry", "jorge", "Félix", "Iván"], "Harry > George > Félix > Iván. El más difícil es Harry."],
    "TLR3_03": ["Mia es más joven que Nina. Oscar es mayor que Nina. Pam es más joven que Mia. ¿Quién es el mayor?", "Óscar > Nina > Mía > Pam. quien esta arriba", ["Óscar", "niña", "Mía", "pam"], "Óscar > Nina > Mía > Pam. El mayor es Óscar."],
    "TLR3_04": ["En una carrera, Raj termina después de Sam. Tina terminó antes que Sam. Uma termina después de Raj. ¿Quién termina primero?", "Primero en orden de llegada = mejor asiento. Cadena: Tina → Sam → Raj → Uma.", ["tina", "Sam", "Raj", "uma"], "Orden: Tina, Sam, Raj, Uma. La primera es Tina."],
    "TLR3_05": ["Víctor gana menos que Wendy. Wendy gana menos que Xavier. Yara gana más que Xavier. ¿Quién gana más?", "Cadena: Víctor < Wendy < Xavier < Yara.", ["Yara", "xavier", "wendy", "Víctor"], "Yara > Xavier > Wendy > Víctor. Yara es la que más gana."],
    "TLR3_06": ["Eve tiene una puntuación más alta que Frank. Grace tiene una puntuación más baja que Frank. Dave tiene una puntuación más alta que Eve. ¿Quién tiene la puntuación más baja?", "Dave > Eva > Frank > Grace. quien esta abajo", ["gracia", "franco", "Eva", "dave"], "Dave > Eva > Frank > Grace. Grace tiene la puntuación más baja."],
    "TLR3_07": ["Lily nada más rápido que Max. Olivia nada más rápido que Lily. Noah nada más lento que Max. ¿Quién nada más lento?", "Por velocidad: Olivia > Lily > Max > Noah.", ["Noé", "máx.", "lirio", "Olivia"], "Olivia > Lily > Max > Noah. El más lento es Noah."],
    "TLR3_08": ["Quinn es más baja que Ruth. Steve es más alto que Tom. Tom es más alto que Ruth. ¿Quién es el más alto?", "Cadena: Steve > Tom > Ruth > Quinn.", ["esteban", "tom", "rut", "quinn"], "Steve > Tom > Ruth > Quinn. El más alto es Steve."],
    "TLR3_09": ["Amy pesa menos que Brian. Clara pesa más que Dan. Dan pesa más que Brian. ¿Quién es el más fácil?", "Clara > Dan > Brian > Amy.", ["amy", "brian", "Dan", "clara"], "Clara > Dan > Brian > Amy. La más fácil es Amy."],
    "TLR3_10": ["Jake corre más lento que Kim. Leo corre más rápido que Mona. Mona corre más rápido que Kim. ¿Quién es el segundo más rápido?", "Leo > Mona > Kim > Jake. ¿Segundo?", ["mona", "kim", "león", "gato"], "Leo > Mona > Kim > Jake. La segunda en velocidad es Mona."],
    "TLR3_11": ["En un grupo de 20 estudiantes, 12 juegan tenis y 10 juegan fútbol. Todo el mundo practica al menos un deporte. ¿Cuántos hacen ambas cosas?", "Ambos = A + B − total (cuando cada uno forma al menos uno).", ["2", "4", "8", "10"], "12 + 10 − 20 = 2. Dos estudiantes practican ambos deportes."],
    "TLR3_12": ["En un grupo de 25 personas, a 18 les gusta el café y a 13 el té. A todos les gusta al menos uno. ¿A cuántas personas les gustan ambos?", "Ambos = café + té − total.", ["6", "5", "7", "8"], "18 + 13 − 25 = 6. A seis personas les gustan ambos."],
    "TLR3_13": ["En una empresa con 35 empleados, 20 hablan francés y 22 alemán. Todos hablan al menos uno. ¿Cuántos hablan ambos?", "Ambos = francés + alemán − total.", ["7", "5", "8", "13"], "20 + 22 − 35 = 7. Siete empleados hablan ambos."],
    "TLR3_14": ["De un grupo de 40 turistas, 28 visitaron el museo y 18 el parque. Todos visitaron al menos un lugar. ¿Cuántos visitaron ambos?", "Ambos = museo + parque − total.", ["6", "10", "8", "4"], "28 + 18 − 40 = 6. Seis turistas visitaron ambos."],
    "TLR3_15": ["En un grupo de 30 lectores, 16 leen ficción y 20 leen no ficción. Todo el mundo lee al menos un tipo. ¿Cuántos leen ambos?", "Ambos = ficción + no ficción − total.", ["6", "4", "10", "14"], "16 + 20 − 30 = 6. Seis lectores leen ambos."],
    "TLR3_16": ["En una fila, Alice es la tercera desde la izquierda y la quinta desde la derecha. ¿Cuántas personas hay en la fila?", "Total = posición izquierda + posición derecha − 1.", ["7", "8", "6", "9"], "3 + 5 − 1 = 7. Hay 7 personas."],
    "TLR3_17": ["En una fila, Bob es el séptimo desde la izquierda y el cuarto desde la derecha. ¿Cuántas personas hay?", "Total = izquierda + derecha − 1.", ["10", "11", "9", "12"], "7 + 4 − 1 = 10. Hay 10 personas."],
    "TLR3_18": ["En fila, Carol ocupa el quinto lugar desde el frente y el noveno desde atrás. ¿Cuántas personas hay en la fila?", "Total = frente + atrás − 1.", ["13", "14", "12", "15"], "5 + 9 − 1 = 13. Hay 13 personas."],
    "TLR3_19": ["De forma consecutiva, David es noveno delante y tercero detrás. ¿Cuántas personas hay?", "Total = frente + atrás − 1.", ["11", "12", "10", "13"], "9 + 3 − 1 = 11. Hay 11 personas."],
    "TLR3_20": ["En fila, Emily ocupa el sexto lugar desde la izquierda y el sexto desde la derecha. ¿Cuántas personas hay?", "Total = izquierda + derecha − 1.", ["11", "12", "10", "13"], "6 + 6 − 1 = 11. Hay 11 personas."],
    "TLR4_01": ["Se comparan cinco personas por peso. E es más duro que A, A que B, C que D, D que B, A que C. Clasifique de más pesado a más liviano.", "Construye la cadena: E > A > C > D > B.", ["E, A, C, D, B", "E, A, D, C, B", "A, E, C, D, B", "E, C, A, D, B"], "E > A > C > D > B. El más difícil es E, el más fácil B."],
    "TLR4_02": ["Cinco corredores terminan una carrera. Sam termina antes que Priya, Priya antes que Quinn, Quinn antes que Tara, Tara antes que Rosa. ¿Quién termina en 3er lugar?", "Orden de llegada: Sam → Priya → Quinn → Tara → Rosa.", ["quinn", "Priya", "país", "Sam"], "Sam, Priya, Quinn, Tara, Rosa. El tercero es Quinn."],
    "TLR4_03": ["Cinco estudiantes tienen puntuaciones diferentes. Jack > Fred > Gina > Iris > Hank. ¿Quién tiene el segundo puntaje más bajo (penúltimo lugar)?", "Número de abajo hacia arriba: Hank, Iris…", ["Iris", "gina", "madeja", "fred"], "La segunda desde abajo (después de Hank) es Iris."],
    "TLR4_04": ["Seis atletas por velocidad: Elena > Diana > Ava > Bella > Chloe > Fiona. Ordene de más rápido a más lento.", "Construye paso a paso.", ["Elena, Diana, Ava, Bella, Chloe, Fiona", "Diana, Elena, Ava, Bella, Chloe, Fiona", "Elena, Ava, Diana, Bella, Chloe, Fiona", "Elena, Diana, Bella, Ava, Chloe, Fiona"], "Elena > Diana > Ava > Bella > Chloe > Fiona."],
    "TLR4_05": ["Cinco ciudades por población: Penny > Liam > Mason > Oliver > Noah. Ordene de más poblado a menos poblado.", "Penny > Liam > Mason > Oliver > Noah.", ["Penny, Liam, Mason, Oliver, Noé", "Liam, Penny, Mason, Oliver, Noah", "Penny, Mason, Liam, Oliver, Noah", "Penny, Liam, Oliver, Mason, Noah"], "Penny > Liam > Mason > Oliver > Noah."],
    "TLR4_06": ["En una empresa con 60 empleados, 38 usan Windows y 30 usan Mac. Todo el mundo utiliza al menos un sistema. ¿Cuántos usan ambos?", "Ambos = Windows + Mac − total.", ["8", "10", "12", "6"], "38 + 30 - 60 = 8."],
    "TLR4_07": ["En una escuela con 80 alumnos, 55 estudian matemáticas y 42 ciencias. Todos estudian al menos una materia. ¿Cuántos estudian ambos?", "Ambos = matemáticas + ciencias − total.", ["17", "15", "20", "23"], "55 + 42 - 80 = 17."],
    "TLR4_08": ["En un club con 75 socios, 50 juegan al ajedrez y 40 a las damas. Todos juegan al menos un juego. ¿Cuántos juegan ambos?", "Ambos = fichas + fichas - total.", ["15", "10", "20", "25"], "50 + 40 - 75 = 15."],
    "TLR4_09": ["En una encuesta realizada a 90 personas, 60 prefieren el chocolate y 52 la vainilla. A todo el mundo le gusta al menos un sabor. ¿A cuántas personas les gustan ambos?", "Ambos = chocolate + vainilla − total.", ["22", "18", "30", "12"], "60 + 52 - 90 = 22."],
    "TLR4_10": ["En un grupo de 100 votantes, 72 apoyan la propuesta A y 65 apoyan la propuesta B. Cada uno apoya al menos una. ¿Cuántos apoyan a ambos?", "Ambos = A + B − total.", ["37", "35", "40", "28"], "72 + 65 - 100 = 37."],
    "TLR4_11": ["En una encuesta, 50 personas: 30 tienen coche, 25 bicicleta, 10 ambas cosas. ¿Cuántos no tienen ninguno?", "Al menos uno = coche + bicicleta – ambos. Ninguno = total - al menos uno.", ["5", "10", "15", "0"], "30 + 25 − 10 = 45 tienen al menos uno. 50 − 45 = 5 no tienen ninguno."],
    "TLR4_12": ["En una clase de 45 estudiantes, 28 aprobaron matemáticas, 20 ciencias y 8 ambas. ¿Cuántos aprobaron exactamente una materia?", "Solo uno = (solo matemáticas) + (solo ciencias).", ["32", "40", "28", "20"], "Sólo matemáticas: 28−8=20. Sólo ciencia: 20−8=12. Total 32."],
    "TLR4_13": ["60 personas: 40 tocan la guitarra, 30 tocan el piano, todos tocan al menos un instrumento. ¿Cuántos cantan exactamente a la una?", "Ambos = guitarra + piano − 60. Exactamente uno = 60 − ambos.", ["50", "60", "40", "30"], "Ambos = 10. Exactamente uno = 50."],
    "TLR4_14": ["55 estudiantes: 32 en el círculo de arte, 28 en música, 12 en ambos. ¿Cuántos no están en ningún círculo?", "Al menos uno = 32+28−12. Ninguno = 55 - esto.", ["7", "5", "10", "3"], "48 tienen al menos un círculo. 55-48=7."],
    "TLR4_15": ["70 personas: 45 leen periódicos, 38 revistas, 20 ambos. ¿Cuánto lee exactamente un chico?", "Exactamente uno = (solo periódico) + (solo revista).", ["43", "63", "50", "33"], "25 + 18 = 43."],
    "TLR4_16": ["Si hace frío, Tom usa una chaqueta. Si lleva chaqueta, lleva paraguas. Hace frío. ¿Qué toma Tom?", "Cadena: frío → chaqueta → paraguas. Modus ponens dos veces.", ["un paraguas", "un sombrero", "nada", "solo la chaqueta"], "Hace frío → chaqueta → paraguas. Así que llévate un paraguas."],
    "TLR4_17": ["Si Alice aprende, asciende. Si aprueba, se gradúa. Si se gradúa, recibe una oferta de trabajo. Alicia está aprendiendo. ¿Cuál es el resultado final?", "Cadena: aprendizaje → promoción → graduación → oferta.", ["Alice recibe una oferta de trabajo", "Alice solo aprueba el examen.", "Alice acaba de graduarse", "No se puede sacar ninguna conclusión"], "Alice recorre toda la cadena hasta la oferta de trabajo."],
    "TLR4_18": ["Si se corta la luz, la computadora se apaga. Si se detiene, perderá el trabajo no guardado. La obra no se perdió. ¿Qué conclusión sacas?", "Modus peaje en cadena.", ["La corriente no cayo", "La corriente bajó", "la computadora se detuvo", "el trabajo esta perdido"], "Trabajo no perdido → la computadora no se apagó → no falló la energía."],
    "TLR4_19": ["Si llueve, el partido se cancela. Si se cancela se devuelven los billetes. Los billetes no fueron devueltos. ¿Qué conclusión?", "No devuelto → el partido no cancelado → no llovió.", ["no llovió", "Llovió", "El partido fue cancelado.", "Las entradas han sido devueltas."], "Peajes en doble modo: no llueve."],
    "TLR4_20": ["Si comes demasiada azúcar, aumentarás de peso. Si aumentas de peso, necesitas hacer ejercicio. Si lo necesitas te apuntas al gimnasio. No te has apuntado al gimnasio. ¿Qué conclusión?", "Modus peaje en cadena.", ["No comiste demasiada azúcar", "comiste demasiada azucar", "has ganado peso", "Te inscribiste en el gimnasio"], "Sin gimnasio → sin necesidad extra → sin engordar → sin exceso de azúcar."],
    "TLR5_01": ["Tres personas: A, B y C. Exactamente una dice la verdad. A dice: «B y C mienten los dos». B dice: «A miente». C dice: «A dice la verdad». ¿Quién dice la verdad?", "Imagina por turnos que solo esa persona dice la verdad y mira si hay contradicciones.", ["B", "A", "C", "Ninguno"], "Si B dice la verdad: A miente, así que no es cierto que B y C mientan los dos — B es sincero ✓. C miente, así que A no dice la verdad ✓. Solo encaja B."],
    "TLR5_02": ["Tres personas: D, E y F. Exactamente una dice la verdad. D dice: «E miente». E dice: «F miente». F dice: «D y E mienten los dos». ¿Quién dice la verdad?", "Prueba cada persona como única veraz.", ["E", "D", "F", "Ninguno"], "Si E dice la verdad: F miente ✓. D dice «E miente» — eso es falso, así que D miente ✓. F miente al decir que D y E mienten los dos, lo cual encaja. Solo E es coherente."],
    "TLR5_03": ["G, H, I: sospechosos. Sólo un culpable. El culpable siempre miente; los inocentes dicen la verdad. G: \"Él es culpable\". H: \"No soy culpable\". Yo: \"G es culpable\". ¿Quién tiene la culpa?", "Adivina quién es el culpable a su vez.", ["GRAMO", "h", "yo", "No se puede determinar"], "Si G es culpable: G miente → H inocente ✓; H y digo la verdad ✓. El resto conduce a contradicciones."],
    "TLR5_04": ["J, K, L. Exactamente uno dice la verdad. J: \"Digo la verdad\". K: «J dice la verdad». L: \"Estoy mintiendo\". ¿Quién está diciendo la verdad?", "Si J fuera honesto, K también lo sería: imposible.", ["l", "j", "k", "Ninguno"], "L honesto → J mentiroso → K mentiroso ✓. Sólo L funciona."],
    "TLR5_05": ["M, N, O. Exactamente uno dice la verdad. M: «Tanto N como O dicen la verdad». N: \"Estoy mintiendo\". O: \"No me importa\". ¿Quién está diciendo la verdad?", "Si M fuera honesto, N y O serían ambos honestos: contradice \"exactamente uno\".", ["norte", "m", "oh", "Ninguno"], "N honesto → M mentiroso; La afirmación de M es falsa → no ambos N,O son honestos → O miente ✓."],
    "TLR5_06": ["Dentro de tres días será miércoles. que dia es hoy", "Cuenta regresiva tres días a partir del miércoles.", ["domingo", "lunes", "sábado", "martes"], "Miércoles −3 días = domingo."],
    "TLR5_07": ["Ayer fue viernes. ¿Qué día será pasado mañana?", "Descúbrelo hoy, luego +2 días.", ["lunes", "domingo", "martes", "sábado"], "Ayer viernes → hoy sábado → pasado mañana lunes."],
    "TLR5_08": ["Hace dos días era lunes. ¿Qué día será dentro de tres días?", "Descubra «hoy» desde «hace dos días», luego +3.", ["sábado", "viernes", "domingo", "jueves"], "Hace dos días = lunes → hoy = miércoles → dentro de tres días = sábado."],
    "TLR5_09": ["Anteayer fue jueves. ¿Qué día será mañana?", "Anteayer = hace dos días.", ["domingo", "sábado", "lunes", "viernes"], "Anteayer jueves → ayer viernes → hoy sábado → mañana domingo."],
    "TLR5_10": ["Dentro de cuatro días será martes. ¿Qué día fue ayer?", "Hoy = martes − 4 días; ayer = hoy − 1.", ["jueves", "viernes", "miércoles", "sábado"], "Hoy = viernes, ayer = jueves."],
    "TLR5_11": ["Seis estudiantes por grados: Fay > Diana > Abby > Brian > Carl > Elena. ¿Quién es el tercero más alto (tercero más alto)?", "Número superior: 1 Fay, 2 Diana, 3…", ["Abby", "diana", "brian", "fay"], "La tercera es Abby."],
    "TLR5_12": ["Cinco frascos: 5>1>2>4>3 en peso. ¿Cuál está en el medio (tercer lugar)?", "Cadena completa 5>1>2>4>3.", ["Tarro 2", "Tarro 1", "Tarro 4", "Tarro 3"], "El tercero en orden es el frasco 2."],
    "TLR5_13": ["Siete personas por edad: T>U>V>W>X>Y>Z. ¿Quién es el cuarto en edad?", "Número en la posición 4 de la cadena.", ["w", "V", "x", "tu"], "El cuarto es W."],
    "TLR5_14": ["Cinco ciudades: E>A>B>D>C por población. ¿Cuál es el menos poblado?", "C está al final de la cadena.", ["Ciudad C", "Ciudad D", "Ciudad B", "Ciudad A"], "El más pequeño es C."],
    "TLR5_15": ["Seis cartas por páginas: T>P>Q>U>R>S. ¿Cuál tiene la segunda menor cantidad (penúltima) páginas?", "Abajo: S mínimo, luego R.", ["Libro R", "Libro S", "El libro U", "El libro Q"], "El segundo desde abajo es R."],
    "TLR5_16": ["Tres cajas: «Manzanas», «Naranjas», «Mezcla». Todas las etiquetas están equivocadas. Saca una manzana del cuadro «Mezcla». ¿Qué hay realmente en la caja con la etiqueta \"Manzanas\"?", "\"Mezcla\" es falsa: la caja es homogénea; sacaste una manzana → ahí están las manzanas.", ["naranjas", "manzanas", "Mezcla", "No se puede determinar"], "El cuadro \"Mezcla\" contiene sólo manzanas. «Naranja» no tiene naranjas → mezcla. \"Apple\" tiene naranjas."],
    "TLR5_17": ["Alice, Bob y Carol trabajan en días diferentes: lunes, martes, miércoles. Alice no trabaja los lunes. Bob no trabaja los martes ni los miércoles. Carol no trabaja los miércoles. ¿Qué día trabaja Carol?", "Comienza con Bob: tiene el único día posible.", ["martes", "lunes", "miércoles", "No se puede determinar"], "Bob solo los lunes → Alice los martes o miércoles → Carol no los miércoles → Carol los martes."],
    "TLR5_18": ["Si P es verdadera, Q es verdadera. Si Q es verdadera, R es falsa. Si R es falso, S es verdadero. P es cierto. ¿Es verdadero o falso?", "Pasa por la cadena P→Q→¬R→S.", ["es verdad", "es falso", "S es desconocido", "S depende de R"], "P → Q → R falso → S verdadero."],
    "TLR5_19": ["Cinco amigos: Alex > Drew > Blake > Casey > Ellie por edad. ¿Quién está en el medio (tercero en edad)?", "El tercero de cinco.", ["blake", "dibujó", "casey", "Álex"], "El tercero es Blake."],
    "TLR5_20": ["En el ranking V,W,X,Y,Z: V antes de W; X inmediatamente después de Y; Z en 3er lugar; W en 5to lugar; Y antes de Z. ¿En qué lugar está V?", "Z=3, W=5; Y antes de Z; X después de Y.", ["4to lugar", "1er lugar", "2do lugar", "3er lugar"], "Y=1, X=2, Z=3, V=4, W=5."],
    "TSR1_01": ["¿Cuántos lados tiene un pentágono?", "El prefijo \"penta-\" se refiere a un número específico.", ["5", "4", "6", "7"], "\"Pentágono\" proviene del griego y significa cinco. Un pentágono tiene exactamente 5 lados."],
    "TSR1_02": ["¿Cuántos lados tiene un hexágono?", "El prefijo \"hexa-\" indica un número; piense en hexadecimal.", ["6", "5", "8", "7"], "\"Hexágono\" proviene del griego y significa seis. Un hexágono tiene 6 lados."],
    "TSR1_03": ["¿Cuántos lados tiene un octágono?", "Piensa en el pulpo: ¿cuántos brazos tiene?", ["8", "6", "10", "7"], "El prefijo «octa-» significa ocho, como en pulpo. Un octágono tiene 8 lados."],
    "TSR1_04": ["¿Cuántos ángulos tiene un triángulo?", "El prefijo «tri-» te da la respuesta directamente.", ["3", "4", "2", "1"], "Un triángulo tiene 3 ángulos, uno en cada vértice donde se encuentran dos lados."],
    "TSR1_05": ["¿Cuántos ángulos tiene un pentágono?", "Cada lado se encuentra con el siguiente en ángulo. Cuente los lados.", ["5", "4", "6", "3"], "Cualquier polígono tiene tantos ángulos como lados. Un pentágono tiene 5 lados y 5 ángulos."],
    "TSR1_06": ["¿Cuántas caras tiene una caja rectangular (prisma rectangular)?", "Piensa arriba, abajo, adelante, atrás, izquierda y derecha.", ["6", "4", "8", "5"], "Un prisma rectangular tiene 6 caras: superior, inferior, frontal, posterior, izquierda, derecha."],
    "TSR1_07": ["¿Cuántos vértices (esquinas) tiene un triángulo?", "Un vértice es el lugar donde se encuentran dos lados. Cuente las esquinas.", ["3", "4", "2", "6"], "Un triángulo tiene 3 vértices, uno en cada esquina."],
    "TSR1_08": ["¿Qué figura 2D tiene exactamente 3 lados y 3 ángulos?", "Es uno de los polígonos más simples.", ["Triangulo", "cuadrado", "Pentágono", "circulo"], "Un triángulo es un polígono con 3 lados y 3 ángulos."],
    "TSR1_09": ["Si doblas una hoja de papel por la mitad, ¿cuántas capas de papel tienes?", "Antes de doblar tienes 1 capa. Duplica el número.", ["2", "1", "3", "4"], "Cada pliegue por la mitad duplica las capas. A partir de 1, un pliegue da 2 capas."],
    "TSR1_10": ["¿Qué forma tiene cada cara de un cubo estándar?", "Todas las caras del cubo son iguales. ¿Qué figura regular tiene 4 lados iguales y 4 ángulos rectos?", ["cuadrado", "Rectángulo", "Triangulo", "circulo"], "El cubo tiene 6 caras y cada una es un cuadrado."],
    "TSR1_11": ["¿Qué cuerpo 3D se ve igual sin importar cómo lo cortes por el centro?", "No tiene aristas, ni picos, es perfectamente redondo.", ["esfera", "Cilindro", "estafa", "cubo"], "La esfera es perfectamente simétrica. Cualquier corte por el centro da un círculo idéntico."],
    "TSR1_12": ["¿Cuántos lados rectos tiene un círculo?", "El círculo es curvo en todas partes. ¿Hay lados rectos?", ["0", "1", "2", "infinito"], "El círculo no tiene lados rectos; es una curva continua sin esquinas ni segmentos rectos."],
    "TSR1_13": ["¿Cuántos lados tiene un triángulo?", "El nombre dice: «tri» significa tres.", ["3", "2", "4", "5"], "Un triángulo es un polígono que tiene exactamente 3 lados."],
    "TSR1_14": ["¿Cuantos lados tiene un cuadrado?", "Piense en una ventana o un tablero de ajedrez.", ["4", "3", "5", "6"], "Un cuadrado tiene 4 lados iguales y 4 ángulos rectos."],
    "TSR1_15": ["¿Cuántos vértices (esquinas) tiene un cuadrado?", "Cuente los puntos donde se encuentran dos lados.", ["4", "3", "5", "6"], "El cuadrado tiene 4 vértices, uno en cada esquina."],
    "TSR1_16": ["¿Cuántos vértices tiene un hexágono?", "Un polígono siempre tiene tantos vértices como lados.", ["6", "5", "8", "4"], "El hexágono tiene 6 lados, es decir, 6 vértices."],
    "TSR1_17": ["Si doblas una hoja por la mitad dos veces, ¿cuántas capas obtienes?", "Cada pliegue duplica el número actual de capas.", ["4", "2", "3", "8"], "Primer pliegue: 1 → 2 capas. Segundo: 2 → 4 capas."],
    "TSR1_18": ["¿Qué figura tiene 4 lados, todos los ángulos son de 90° y los lados opuestos son paralelos?", "Es la forma más común para puertas, biombos y libros.", ["Rectángulo", "trapecio", "rombo", "paralelogramo"], "El rectángulo tiene 4 lados, opuestos paralelos, todos los ángulos interiores miden 90°."],
    "TSR1_19": ["¿Cuántas esquinas tiene un rectángulo?", "Una esquina es donde dos lados se encuentran en ángulo.", ["4", "2", "3", "5"], "El rectángulo tiene 4 esquinas (vértices), una en cada ángulo recto."],
    "TSR1_20": ["¿Qué figura 2D tiene todos los puntos del contorno a la misma distancia del centro?", "Piensa en una moneda vista desde arriba o en una pizza.", ["circulo", "elipse", "cuadrado", "Ovalado"], "Una circunferencia es el conjunto de puntos que equidistan del centro. Esa distancia constante es el radio."],
    "TSR2_01": ["¿Cuántos lados tiene un prisma rectangular (caja)?", "Cuente los bordes de la cara superior e inferior y los bordes verticales que los conectan.", ["12", "8", "10", "6"], "Prisma rectangular: 4 aristas superiores + 4 inferiores + 4 verticales = 12 aristas."],
    "TSR2_02": ["¿Cuántos vértices tiene un prisma rectangular?", "Cuente las esquinas de las caras superior e inferior por separado.", ["8", "6", "10", "12"], "4 puntos arriba + 4 puntos abajo = 8 puntos."],
    "TSR2_03": ["¿Cuántas caras tiene un prisma pentagonal?", "Un prisma de base de n lados tiene n caras rectangulares laterales más 2 bases.", ["7", "5", "10", "6"], "2 bases pentagonales + 5 caras rectangulares laterales = 7 caras."],
    "TSR2_04": ["¿Cuántas aristas tiene un prisma triangular?", "Cuente los bordes de cada base triangular, luego los bordes que las conectan.", ["9", "6", "8", "12"], "3 aristas arriba + 3 abajo + 3 verticales = 9 aristas."],
    "TSR2_05": ["¿Cuántos vértices tiene un prisma triangular?", "Cada base triangular trae sus propios vértices.", ["6", "5", "8", "9"], "3 púas en cada base: 3 + 3 = 6 púas."],
    "TSR2_06": ["Si 4 cubos idénticos están en línea recta y cada uno comparte una cara con el siguiente, ¿cuántas caras son visibles en total (incluida la inferior)?", "Comienza con caras de 4×6 y luego resta las caras ocultas en cada unión.", ["18", "20", "16", "24"], "4 cubos: 24 caras. 3 uniones × 2 caras ocultas = 6. 24 − 6 = 18 visibles."],
    "TSR2_07": ["¿Cuántas caras tiene un prisma hexagonal?", "El prisma de base n-gonal tiene n + 2 caras.", ["8", "6", "12", "10"], "2 bases hexagonales + 6 caras rectangulares = 8 caras."],
    "TSR2_08": ["¿Cuántas aristas tiene un prisma pentagonal?", "Para un prisma con base de n lados: aristas totales = 3n.", ["15", "10", "12", "20"], "5 arriba + 5 abajo + 5 verticales = 3 × 5 = 15 aristas."],
    "TSR2_09": ["¿Cuántos vértices tiene un prisma pentagonal?", "El prisma duplica los vértices del polígono base.", ["10", "12", "8", "15"], "5 púas por base × 2 bases = 10 púas."],
    "TSR2_10": ["¿Cuántas aristas tiene una pirámide con base cuadrada?", "Cuente los bordes de la base, luego los bordes desde las esquinas de la base hasta la parte superior.", ["8", "5", "6", "10"], "4 bordes en la base + 4 bordes laterales hacia arriba = 8 bordes."],
    "TSR2_11": ["¿Cuántos vértices tiene una pirámide de base cuadrada?", "¡No olvides el consejo principal!", ["5", "4", "6", "8"], "4 esquinas en la base + 1 parte superior = 5 partes superiores."],
    "TSR2_12": ["¿Cuántas caras tiene una pirámide de base cuadrada?", "Cuenta la base y cada cara lateral triangular.", ["5", "4", "6", "8"], "1 base cuadrada + 4 caras triangulares = 5 caras."],
    "TSR2_13": ["¿Cuántas aristas tiene un prisma hexagonal?", "Fórmula: aristas = 3 × el número de lados de la base.", ["18", "12", "24", "15"], "6 + 6 + 6 = 3 × 6 = 18 aristas."],
    "TSR2_14": ["¿Cuántos vértices tiene un prisma hexagonal?", "Cada base hexagonal tiene 6 esquinas.", ["12", "8", "6", "18"], "6 púas por base × 2 bases = 12 púas."],
    "TSR2_15": ["Si 5 cubos idénticos están alineados y comparten caras, ¿cuántas caras son visibles en total (incluida la parte inferior)?", "5 cubos = 30 caras. ¿Cuántas uniones y cuántas caras esconde cada una?", ["22", "20", "24", "26"], "30 caras − 4 uniones × 2 = 30 − 8 = 22 visibles."],
    "TSR2_16": ["¿Cuántas caras tiene un prisma octogonal?", "Fórmula del prisma: n + 2 caras para una base de n lados.", ["10", "8", "12", "16"], "2 bases octogonales + 8 caras laterales rectangulares = 10 caras."],
    "TSR2_17": ["¿Cuántas aristas tiene un prisma octogonal?", "Fórmula: 3n aristas para una base con n lados.", ["24", "16", "20", "32"], "3 × 8 = 24 aristas."],
    "TSR2_18": ["¿Cuántos vértices tiene una pirámide triangular (tetraedro)?", "Base triangular y un punto arriba.", ["4", "3", "5", "6"], "Tetraedro: 3 vértices en la base + 1 vértice = 4 vértices."],
    "TSR2_19": ["Fórmula de Euler: V − E + F = 2 para poliedros convexos (E = número de aristas). Si un poliedro tiene 6 vértices y 12 aristas, ¿cuántas caras tiene?", "Reorganizar: F = 2 − V + E.", ["8", "6", "10", "7"], "F = 2 − 6 + 12 = 8 caras (por ejemplo: cubo regular u octaedro)."],
    "TSR2_20": ["¿Cuántas diagonales tiene un cuadrado?", "Una diagonal conecta dos vértices no adyacentes. El cuadrado tiene 4 vértices.", ["2", "4", "1", "3"], "El cuadrado tiene 2 diagonales, cada una de las cuales conecta esquinas opuestas."],
    "TSR3_01": ["Se pinta un cubo de 3×3×3 en todas las caras y luego se corta en 27 cubos pequeños. ¿Cuántos cubos tienen al menos una cara pintada?", "Sólo el cubo en el centro exacto de la cuadrícula de 3×3×3 no tiene pintura. ¿Cuántos cubos no hay en el centro?", ["26", "24", "20", "27"], "Un solo cubo (el centro) tiene 0 caras pintadas. Entonces 27 − 1 = 26 tienen al menos una cara pintada."],
    "TSR3_02": ["Se pinta todas las caras de un cubo de 3×3×3 y se corta en 27 cubos pequeños. ¿Cuántas caras unitarias pintadas tienen los 27 cubos en total?", "Cada una de las 6 caras del cubo grande es una cuadrícula de 3 × 3, por lo que hay 9 caras unitarias pintadas por cara.", ["54", "48", "36", "27"], "6 caras × 9 = 54 caras de la unidad pintadas."],
    "TSR3_03": ["El cubo pintado de 3×3×3 se corta en 27 cubos pequeños. ¿Cuántos cubos tienen como máximo una cara pintada?", "Cuenta los cubos con 0 caras pintadas y exactamente 1, luego suma.", ["7", "6", "8", "12"], "1 cubo con 0 caras (el centro) + 6 cubos con exactamente 1 (los centros de las caras). Total: 1 + 6 = 7."],
    "TSR3_04": ["El cubo pintado de 3×3×3 se corta en 27 cubos pequeños. ¿Cuántos cubos tienen al menos 2 caras pintadas?", "Son los cubos de las esquinas (3 lados) y los del borde (2 lados).", ["20", "12", "8", "18"], "8 esquinas (3 pintadas) + 12 aristas × 1 cubo central de 2 caras = 20 cubos con 2 o más caras pintadas."],
    "TSR3_05": ["Si cortas un cubo con un plano paralelo a una de las caras, ¿qué forma tiene la sección?", "Cortar paralelo a una cara cuadrada da una forma congruente con esa cara.", ["cuadrado", "Rectángulo", "Triangulo", "Hexágono"], "El plano paralelo a una cara corta cuatro aristas iguales y da un cuadrado."],
    "TSR3_06": ["Si cortas un cilindro con un plano perpendicular a su eje, ¿qué forma tiene la sección?", "El eje pasa por los centros de las dos bases circulares.", ["circulo", "elipse", "Rectángulo", "Ovalado"], "El corte perpendicular al eje es paralelo a las bases: obtienes un círculo."],
    "TSR3_07": ["Si cortas un cono con un plano paralelo a la base circular, ¿qué forma obtienes?", "La base del cono es un círculo. El corte paralelo da una forma similar.", ["circulo", "elipse", "Triangulo", "parábola"], "El plano paralelo a la base corta al cono formando un círculo (más pequeño que la base)."],
    "TSR3_08": ["¿Cuántos vértices tiene una esfera?", "La parte superior es donde se unen los bordes. ¿La esfera tiene aristas?", ["0", "1", "2", "infinito"], "La esfera es una superficie lisa, sin aristas, por lo tanto sin picos."],
    "TSR3_09": ["¿Cuántas aristas tiene una esfera?", "La arista es el segmento donde se encuentran dos caras planas.", ["0", "1", "2", "infinito"], "La esfera no tiene caras planas, por lo que no tiene aristas."],
    "TSR3_10": ["¿Cuántas caras tiene una pirámide hexagonal?", "La pirámide tiene 1 base más caras triangulares laterales, una por lado de la base.", ["7", "6", "8", "12"], "1 base hexagonal + 6 caras triangulares laterales = 7 caras."],
    "TSR3_11": ["¿Cuántas aristas tiene una pirámide hexagonal?", "Cuente las aristas de la base y las aristas desde cada vértice de la base hasta el vértice de la pirámide.", ["12", "6", "8", "18"], "6 bordes en la base + 6 bordes laterales hacia arriba = 12 bordes."],
    "TSR3_12": ["¿Cuántos vértices tiene una pirámide hexagonal?", "Cuente los vértices de la base y el único vértice superior.", ["7", "6", "8", "12"], "6 púas en la base + 1 púa = 7 púas. (Verificación de Euler: 7 − 12 + 7 = 2 ✓)"],
    "TSR3_13": ["Si cortas un cubo desde la mitad de una arista hasta la mitad de la arista paralela opuesta, ¿qué forma puede tener la sección?", "Al cortar dos bordes paralelos se obtiene un cuadrilátero plano.", ["Rectángulo", "Triangulo", "Pentágono", "circulo"], "El plano mediante dos aristas paralelas opuestas da una sección rectangular."],
    "TSR3_14": ["¿Cuántas caras tiene una pirámide de base pentagonal?", "1 base + caras laterales (una por lado de la base).", ["6", "5", "7", "10"], "1 base pentagonal + 5 caras triangulares = 6 caras."],
    "TSR3_15": ["¿Cuántas aristas tiene una pirámide con base pentagonal?", "Para pirámide con base de n lados: 2n aristas.", ["10", "5", "8", "15"], "5 aristas en la base + 5 lados = 10 aristas."],
    "TSR3_16": ["¿Cuántos vértices tiene una pirámide de base pentagonal?", "Los vértices de la base más el vértice superior.", ["6", "5", "7", "10"], "5 púas en la base + 1 púa = 6 púas. (Comprueba: 6 − 10 + 6 = 2 ✓)"],
    "TSR3_17": ["Usando la fórmula de Euler (V − E + F = 2), si un poliedro tiene 5 vértices y 8 aristas, ¿cuántas caras tiene?", "Resuelva para F: F = 2 − V + E.", ["5", "4", "6", "7"], "F = 2 − 5 + 8 = 5 (ej: pirámide con base cuadrada: 5 vértices, 8 aristas, 5 caras)."],
    "TSR3_18": ["¿Cuántas diagonales tiene un hexágono regular?", "Para un polígono con n lados: n(n − 3) / 2.", ["9", "6", "12", "3"], "Diagonales = 6 × (6 − 3) / 2 = 9."],
    "TSR3_19": ["En un cubo pintado de 3×3×3 cortado en 27 cubos, ¿cuántas caras pintadas en total tienen solo los 8 cubos de las esquinas?", "Cada cubo de esquina tiene exactamente 3 caras pintadas.", ["24", "8", "12", "18"], "8 esquinas × 3 caras = 24 caras pintadas en las esquinas."],
    "TSR3_20": ["¿Cuántas diagonales tiene un pentágono regular?", "Utilice n(n − 3) / 2 con n = 5.", ["5", "4", "6", "3"], "Diagonales = 5 × (5 − 3) / 2 = 5."],
    "TSR4_01": ["Se pinta un cubo de 4×4×4 en todas las caras y luego se corta en 64 cubos pequeños. ¿Cuántos cubos tienen al menos una cara pintada?", "El interior sin pintar forma un cubo más pequeño con lado (4 − 2) = 2.", ["56", "48", "52", "60"], "Cubos con 0 pintura en su interior = 2³ = 8. Con al menos 1 cara pintada: 64 − 8 = 56."],
    "TSR4_02": ["El cubo pintado de 4×4×4 se corta en 64 cubos pequeños. ¿Cuántos cubos tienen al menos 2 caras pintadas?", "Cubos de esquina (3 caras) y cubos de arista (2 caras). Colecciónalas.", ["32", "24", "36", "28"], "Esquinas: 8. Aristas: 12 × 2 cubos medianos = 24. Total: 8 + 24 = 32."],
    "TSR4_03": ["El cubo pintado de 4×4×4 se corta en 64 cubos pequeños. ¿Cuántas caras unitarias pintadas tienen todos los cubos en total?", "Cada una de las 6 caras del cubo grande es una cuadrícula de 4×4.", ["96", "64", "72", "108"], "6 × 16 = 96. (Compruebe: 8 × 3 + 24 × 2 + 24 × 1 = 96 ✓)"],
    "TSR4_04": ["El cubo pintado de 4×4×4 se corta en 64 cubos pequeños. ¿Cuántos cubos tienen como máximo una cara pintada?", "Suma los cubos con 0 caras pintadas y exactamente 1.", ["32", "24", "28", "36"], "0 pintados: 8 (interiores 2×2×2). 1 teñido: 24 (caras centrales). Total: 32."],
    "TSR4_05": ["Si quitas un cubo de esquina de un cubo de 3×3×3, ¿cuántas caras de los cubos unitarios son visibles en el sólido restante (incluido el fondo)?", "Al eliminar la esquina, pierdes 3 caras exteriores pero revelas 3 caras interiores previamente ocultas.", ["54", "51", "57", "48"], "Área inicial: 6 × 9 = 54. En la esquina: −3 afuera + 3 recién visibles adentro = 0 neto. Sigo teniendo 54."],
    "TSR4_06": ["¿Cuántas diagonales tiene un octágono regular?", "Fórmula n(n − 3) / 2 con n = 8.", ["20", "16", "24", "8"], "Diagonales = 8 × 5 / 2 = 20."],
    "TSR4_07": ["¿Cuántas diagonales espaciales tiene un cubo? (La diagonal espacial pasa por el interior desde un vértice al vértice opuesto).", "El cubo tiene 8 vértices. Cada diagonal espacial conecta un vértice con su opuesto.", ["4", "6", "8", "12"], "El cubo tiene 4 diagonales espaciales, cada una de las cuales pasa por el centro."],
    "TSR4_08": ["¿Cuántas diagonales de caras tiene un cubo en total?", "Cada cara es cuadrada. ¿Cuántas diagonales tiene el cuadrado? Multiplica por 6.", ["12", "6", "8", "24"], "6 caras × 2 diagonales = 12 diagonales en caras."],
    "TSR4_09": ["¿Cuántas caras tiene un octaedro regular (dos pirámides cuadradas unidas por la base)?", "Cada pirámide trae 4 caras triangulares. La base cuadrada común está en el interior.", ["8", "6", "12", "20"], "El octaedro regular tiene 8 caras triangulares equiláteras."],
    "TSR4_10": ["¿Cuántas aristas tiene un octaedro regular?", "Utilice la fórmula de Euler si conoce V = 6 y F = 8.", ["12", "8", "6", "24"], "E = V + F − 2 = 6 + 8 − 2 = 12 aristas."],
    "TSR4_11": ["¿Cuántos vértices tiene un octaedro regular?", "Pensemos en dos pirámides unidas por su base. Cuente los distintos picos.", ["6", "8", "12", "4"], "4 vértices alrededor del ecuador cuadrado + 1 vértice arriba + 1 abajo = 6."],
    "TSR4_12": ["Si 8 cubos unitarios forman un cubo de 2×2×2, ¿cuántas caras de los cubos unitarios son visibles en el exterior (incluida la parte inferior)?", "El resultado es un cubo con lado 2. ¿Área total en caras unitarias?", ["24", "28", "32", "20"], "6 × (2×2) = 24 caras unitarias."],
    "TSR4_13": ["Un dodecaedro regular tiene 12 caras pentagonales y 30 aristas. Con la fórmula de Euler ¿cuántos vértices tiene?", "V = 2 + mi - F.", ["20", "12", "24", "30"], "V = 2 + 30 − 12 = 20 vértices."],
    "TSR4_14": ["Un icosaedro regular tiene 20 caras triangulares y 12 vértices. ¿Cuántas aristas tiene?", "mi = V + F - 2.", ["30", "20", "24", "36"], "mi = 12 + 20 − 2 = 30 aristas."],
    "TSR4_15": ["En un cubo pintado de 4×4×4, ¿cuántas caras pintadas tienen en total los 8 cubos de las esquinas?", "Cualquier cubo de esquina tiene exactamente 3 caras pintadas, independientemente del tamaño del cubo grande.", ["24", "8", "12", "32"], "8 × 3 = 24."],
    "TSR4_16": ["En el mismo cubo de 4×4×4, ¿cuántas caras pintadas tienen los cubos de aristas (aquellos que tienen exactamente 2 caras pintadas)?", "Cuantos cubos hay en las aristas, luego multiplica por 2.", ["48", "24", "36", "60"], "24 cubos en las aristas (12 aristas × 2), cada uno con 2 caras pintadas: 24 × 2 = 48."],
    "TSR4_17": ["Si se corta un cubo con un plano mediante tres aristas partiendo del mismo vértice, ¿qué forma tiene la sección?", "Los tres medios están equidistantes de la esquina. ¿Qué triángulo tiene todos los lados iguales?", ["Triángulo equilátero", "cuadrado", "triangulo rectángulo", "hexágono regular"], "El avión corta los tres bordes de las esquinas por igual: se obtiene un triángulo equilátero."],
    "TSR4_18": ["¿Cuántas diagonales tiene un decágono regular (10 lados)?", "Fórmula: n(n − 3) / 2.", ["35", "30", "40", "25"], "10×7/2 = 35."],
    "TSR4_19": ["Un prisma tiene exactamente 10 vértices. ¿Qué forma tiene la base?", "El prisma base de n lados tiene 2n vértices.", ["Pentágono", "cuadrado", "Hexágono", "Triangulo"], "2n = 10 → n = 5. La base es un pentágono."],
    "TSR4_20": ["Una pirámide tiene exactamente 7 caras. ¿Qué forma tiene la base?", "La pirámide de base de n lados tiene n + 1 caras.", ["Hexágono", "Pentágono", "heptágono", "Octágono"], "n + 1 = 7 → n = 6. La base es un hexágono."],
    "TSR5_01": ["Se pinta un cubo de 5×5×5 en todas las caras y luego se corta en 125 cubos pequeños. ¿Cuántos cubos tienen exactamente 2 caras pintadas?", "Los cubos en los bordes (no en las esquinas) tienen 2 caras pintadas. Fórmula: 12(n − 2).", ["36", "24", "48", "30"], "12 × (5 − 2) = 36."],
    "TSR5_02": ["El cubo pintado de 5×5×5 se corta en 125 cubos pequeños. ¿Cuántos cubos tienen exactamente 3 caras pintadas?", "Sólo los cubos de las esquinas tienen 3 caras pintadas. ¿Cuántas esquinas tiene cualquier cubo?", ["8", "12", "20", "6"], "Cualquier cubo tiene 8 esquinas. Entonces 8 cubos con exactamente 3 caras pintadas."],
    "TSR5_03": ["El cubo pintado de 5×5×5 se corta en 125 cubos pequeños. ¿Cuántos cubos tienen al menos una cara pintada?", "Resta los cubos del interior completamente sin pintar: (n − 2)³.", ["98", "96", "100", "90"], "Dentro = 3³ = 27. 125 − 27 = 98."],
    "TSR5_04": ["El cubo pintado de 5×5×5 se corta en 125 cubos pequeños. ¿Cuántas caras unitarias pintadas tienen todos los cubos en total?", "Cada una de las 6 caras del cubo grande es una cuadrícula de 5×5.", ["150", "125", "144", "162"], "6 × 25 = 150."],
    "TSR5_05": ["Un cubo pintado de 6×6×6 se corta en 216 cubos pequeños. ¿Cuantos tienen exactamente 2 caras pintadas?", "12(norte − 2) con norte = 6.", ["48", "36", "60", "24"], "12 × 4 = 48."],
    "TSR5_06": ["El cubo pintado de 6×6×6 se corta en 216 cubos pequeños. ¿Cuantos tienen exactamente 1 cara pintada?", "6(norte − 2)² con norte = 6.", ["96", "72", "108", "84"], "6 × 16 = 96."],
    "TSR5_07": ["El cubo pintado de 6×6×6 se corta en 216 cubos pequeños. ¿Cuántos no tienen pintura en la cara?", "Bloque interior: (n − 2)³.", ["64", "48", "36", "27"], "(6 − 2)³ = 64."],
    "TSR5_08": ["El cubo pintado de 6×6×6 se corta en 216 cubos pequeños. ¿Cuantos tienen exactamente 3 caras pintadas?", "Las esquinas son siempre 8, independientemente del tamaño.", ["8", "12", "6", "24"], "8 cubos con 3 caras pintadas. (Comprueba: 8+48+96+64=216 ✓)"],
    "TSR5_09": ["El cubo pintado de 6×6×6 se corta en 216 cubos pequeños. ¿Cuántas caras de unidad pintadas tienen en total?", "Cada cara del cubo grande es una cuadrícula de 6×6.", ["216", "200", "192", "240"], "6 × 36 = 216."],
    "TSR5_10": ["En un cubo pintado de 10×10×10 cortado en 1000 cubos, ¿cuántas 2 caras pintadas hay exactamente?", "12(n − 2) para los cubos en las aristas.", ["96", "120", "80", "108"], "12 × 8 = 96."],
    "TSR5_11": ["En el mismo cubo de 10×10×10, ¿cuántos cubos pequeños tienen exactamente 1 cara pintada?", "6(n − 2)² para los centros de las caras.", ["384", "360", "400", "480"], "6 × 64 = 384."],
    "TSR5_12": ["¿Cuántos cubos pequeños no tienen ninguna cara pintada?", "El interior es un cubo con lado (n − 2).", ["512", "480", "500", "343"], "(10 − 2)³ = 512."],
    "TSR5_13": ["¿Cuál de estas formas PUEDE ser la sección de un cubo?", "Un plano puede cortar como máximo 6 caras. ¿Puedes atravesar los 6 bordes?", ["hexágono regular", "Pentágono regular", "Octágono regular", "elipse"], "Por medio de 6 aristas se obtiene un hexágono regular. La simetría del cubo no da pentágonos, octágonos (máximo 6 lados) ni curvas."],
    "TSR5_14": ["¿Cuál es el número máximo de lados de una sección plana de un cubo?", "El polígono de sección gana un lado por cada cara que se cruza.", ["6", "4", "8", "12"], "El cubo tiene 6 caras, como máximo un hexágono (6 lados)."],
    "TSR5_15": ["El dodecaedro regular tiene 12 caras pentagonales. Cada cara tiene 5 aristas, pero cada arista es común a 2 caras. ¿Cuántas aristas tiene?", "12 × 5 lugares de borde, cada borde contó dos veces.", ["30", "24", "36", "60"], "12 × 5 / 2 = 30 aristas."],
    "TSR5_16": ["En un cubo pintado de 7×7×7, cortado en 343 cubos, ¿cuántas 2 caras pintadas hay exactamente?", "12(norte − 2) con norte = 7.", ["60", "48", "72", "36"], "12 × 5 = 60."],
    "TSR5_17": ["En el cubo de 7×7×7, ¿cuántos cubos pequeños no tienen la cara pintada?", "(norte − 2)³.", ["125", "64", "100", "27"], "5³ = 125."],
    "TSR5_18": ["Para el cubo pintado n×n×n, el número de cubos con exactamente 1 cara pintada es 6(n − 2)². ¿Por qué hay 96 en la ecuación?", "6(norte − 2)² = 96 → (norte − 2)² = 16.", ["6", "5", "7", "8"], "norte - 2 = 4 → norte = 6."],
    "TSR5_19": ["¿Cuál es el número máximo de lados de una sección que pasa por un prisma triangular?", "El prisma triangular tiene 5 caras (2 triángulos + 3 rectángulos). ¿Puede un plan eliminar los 5?", ["5", "4", "3", "6"], "Un plano inclinado puede cortar ambas bases y las 3 caras laterales (sección pentagonal, máximo 5)."],
    "TSR5_20": ["En el cubo pintado de 7×7×7, ¿cuántas caras unitarias pintadas tienen los 343 cubos en total?", "Cada una de las 6 caras del cubo grande es una cuadrícula de 7×7.", ["294", "252", "300", "343"], "6 × 49 = 294."],
    "TMP1_1": ["Un granjero tiene 12 ovejas. Todos menos 5 mueren. ¿Cuántas ovejas quedan?", "Concéntrese en \"todos menos 5\".", ["5", "7", "12", "0"], "\"Todos menos 5 mueren\" significa que 5 sobreviven. La respuesta es 5, no 12 menos 5."],
    "TMP1_2": ["En una carrera adelantas al tercero. ¿Dónde estás ahora?", "¿Qué sucede cuando adelantas a alguien? ¿Ocupas su lugar?", ["el tercero", "el 2do", "el 4to", "el 1er"], "Cuando pasas a la persona en tercer lugar, tomas su lugar: pasas a ser tercero, no segundo."],
    "TMP1_3": ["¿Cuántos cumpleaños tiene una persona en promedio?", "Sólo naces una vez.", ["1", "alrededor de 75", "365", "Depende de la edad"], "Todo el mundo tiene un solo cumpleaños: el día en que nació. El resto son aniversarios de ese día."],
    "TMP1_4": ["Si tienes 5 naranjas y tomas 2 ¿cuántas tienes TÚ?", "¿Quién se llevó las naranjas?", ["2", "3", "5", "0"], "Tomaste 2 naranjas, entonces tienes 2. La pregunta es cuántas tienes, no cuántas quedan."],
    "TMP1_5": ["A es padre de B, pero B no es hijo de A. ¿Cómo es eso posible?", "Todas las variantes de género para B.", ["B es la hija de A.", "A no es realmente el padre de B.", "B es adoptado", "son parientes adoptivos"], "B es una niña, es hija de A. No todos los niños son niños."],
    "TMP1_6": ["¿Cuántas veces puedes restar 10 de 100?", "Después de la primera caída, ¿quedan 100?", ["1", "10", "9", "Desde el infinito"], "Sólo una vez; después tienes 90 y restas 10 a 90, no 100."],
    "TMP1_7": ["Si un gallo pone un huevo sobre el tejado, ¿hacia dónde rueda el huevo?", "¿Qué es exactamente un gallo?", ["Los gallos no ponen huevos", "Izquierda", "Derecha", "Se queda arriba"], "Los gallos son machos y no ponen huevos. La premisa es imposible."],
    "TMP1_8": ["¿Qué pesa más: una libra de plumas o una libra de ladrillos?", "Mire de cerca la unidad de medida.", ["igualmente", "los ladrillos", "plumas", "depende"], "Una libra es una libra, independientemente del material. Ambos pesan exactamente una libra."],
    "TMP1_9": ["Una camisa costaba $50 y tiene un 50% de descuento. ¿Cuanto pagas?", "Calcula el 50% del precio original.", ["$25", "$50", "$30", "$15"], "50% de $50 = $25."],
    "TMP1_10": ["Estás en una habitación oscura con una vela, una lámpara de aceite y una chimenea. Sólo tienes una coincidencia. ¿Qué enciendes la primera vez?", "Tienes que encender algo antes que nada.", ["el partido", "la vela", "la lámpara", "la chimenea"], "Primero tienes que encender la cerilla para poder encender el resto."],
    "TMP1_11": ["Un avión se estrella justo en la frontera de dos países. ¿Dónde entierras a los supervivientes?", "Lea atentamente: ¿a quién vamos a enterrar?", ["No entierres a los supervivientes", "En el país de salida", "En el país de destino", "en la frontera"], "Los supervivientes están vivos; no los entierren."],
    "TMP1_12": ["¿Cuántos animales de cada especie llevó Moisés al arca?", "Comprueba el nombre en la pregunta.", ["Ninguno: fue Noé, no Moisés", "2", "7", "1"], "Moisés no tenía un arca; Noé sí la tenía. La pregunta usa el nombre incorrecto para engañarlo."],
    "TMP1_13": ["Hay 10 pájaros en una cerca. Tira uno. ¿Cuántos quedan en la valla?", "¿Cómo reaccionan los demás ante el tiroteo?", ["0", "9", "10", "1"], "El ruido los asusta a todos. No queda ninguno."],
    "TMP1_14": ["Un granjero tiene 20 vacas. Todos menos 12 mueren. ¿Cuantos quedan?", "\"Todos menos 12\".", ["12", "8", "20", "0"], "Sobrevivo 12."],
    "TMP1_15": ["¿Qué siempre sube y nunca baja?", "Algo que sólo crece con el tiempo.", ["tu edad", "un globo", "el sol", "la temperatura"], "La edad sólo aumenta."],
    "TMP1_16": ["Una niña golpea la pelota a 3 m de distancia. Vuelve a ella sin muro, sin otra persona, sin giro. ¿Cómo?", "¿De qué manera la golpeó?", ["La golpeó verticalmente hacia arriba.", "el viento", "Saltó del árbol", "la pendiente"], "Él la levantó; la gravedad lo hizo regresar."],
    "TMP1_17": ["¿Qué tiene cabeza y cola pero no cuerpo?", "Objetos ordinarios, no animales.", ["una moneda", "una serpiente", "una aguja", "un cometa"], "La moneda tiene cara (cabeza) y cola (cola), sin cuerpo."],
    "TMP1_18": ["El médico te da 5 pastillas: una cada hora. ¿Cuánto dura el tratamiento?", "¿Cuándo tomas tu primera pastilla?", ["4 horas", "5 horas", "6 horas", "3 horas"], "Hora 0, 1, 2, 3, 4: las últimas 4 horas entre la una y las cinco. Total 4 horas desde el inicio."],
    "TMP1_19": ["Tienes un bol con 6 huevos y sacas 2. ¿Cuántos tienes?", "¿Dónde están los huevos que sacaste?", ["2", "4", "6", "0"], "Sacaste 2 huevos, así que tienes 2. En el bol quedan 4, pero la pregunta es cuántos tienes tú."],
    "TMP1_20": ["Un niño tiene 4 años, su hermana tiene la mitad de su edad. Cuando el niño tenga 100 años, ¿cuántos años tendrá la hermana?", "La diferencia de edad sigue siendo la misma.", ["98", "50", "100", "96"], "The sister is 2 years younger (4÷2=2). 100 - 2 = 98."],
    "TMP2_1": ["Un bolígrafo y una libreta juntos cuestan $1,10. El cuaderno cuesta $1,00 más que el bolígrafo. ¿Cuanto cuesta el bolígrafo?", "Sea x el precio del bolígrafo; el cuaderno es x + $1.00.", ["$0.05", "$0.10", "$1.00", "$0.50"], "x + (x + 1) = 1,10 → 2x = 0,10 → x = $0,05."],
    "TMP2_2": ["El médico te da 3 pastillas: una cada 45 minutos. ¿Cuánto tiempo se tarda?", "¿Cuándo tomas tu primera pastilla?", ["90 minutos", "135 minutos", "45 minutos", "120 minutos"], "A los 0, 45 y 90 minutos, pasan un total de 90 minutos."],
    "TMP2_3": ["5 trabajadores construyen 5 muros en 5 días. ¿Cuánto tiempo les toma a 10 trabajadores construir 10 muros?", "¿Cuánto le cuesta a un trabajador construir un muro?", ["5 dias", "10 dias", "2,5 días", "1 dia"], "Cada uno construye 1 muro en 5 días. 10 personas, 10 paredes paralelas, también 5 días."],
    "TMP2_4": ["Dos monedas equivalen a 30 centavos. Uno no es un centavo (5 ¢). ¿Cuáles son las monedas?", "\"Uno no vale cinco centavos\", ¿qué es el otro?", ["25¢ y 5¢ (cuarto + níquel)", "Dos monedas de 10¢", "50¢", "10¢ y 5¢"], "Uno es una moneda de veinticinco centavos (25 centavos), no una moneda de cinco centavos; el otro es níquel (5¢). Total 30¢."],
    "TMP2_5": ["Multiplica todos los dígitos del teclado de un teléfono (0–9). ¿Cuál es el producto?", "¿Qué pasa cuando multiplicas por un número determinado?", ["0", "3.628.800", "362.880", "45"], "Entre los números está el 0. Cualquier producto que incluya 0 es 0."],
    "TMP2_6": ["Una familia tiene 4 niños y 3 niñas. Cada niño tiene tantas hermanas como hermanos. Cada niña tiene el doble de hermanos que de hermanas. ¿Cuántos niños hay?", "Cuente desde la perspectiva de cada niño.", ["7", "8", "6", "10"], "Niño: 3 hermanos, 3 hermanas ✓. Niña: 4 hermanos, 2 hermanas (4 = 2×2) ✓. Total 7."],
    "TMP2_7": ["Un tren eléctrico va hacia el norte. El viento sopla del oeste. ¿A dónde va el humo?", "¿Qué tipo de propulsión tiene el tren?", ["no hay humo", "Oeste", "Norte", "Este"], "El tren eléctrico no quema combustible, no produce humo."],
    "TMP2_8": ["8 personas construyen un muro en 10 horas. ¿Cuánto tiempo se tarda con 4 personas?", "La mitad de la gente duplica el tiempo.", ["20 horas", "5 horas", "40 horas", "10 horas"], "10 × 2 = 20 horas."],
    "TMP2_9": ["¿Cuántos meses del año tienen (al menos) 30 días?", "Algunos meses tienen más de 30 días.", ["11", "4", "6", "7"], "Todos los meses tienen al menos 30 días excepto febrero. Entonces 11 meses."],
    "TMP2_10": ["Cava 6 hoyos: 3 grandes y 3 pequeños. cuantos agujeros tienes", "¿El tamaño cambia el hecho de que sea un agujero?", ["6", "3", "9", "0"], "Los 6 hoyos."],
    "TMP2_11": ["¿Puedes nombrar tres días seguidos sin lunes, martes, miércoles, jueves, viernes, sábado y domingo?", "Términos relativos, no nombres propios.", ["Ayer, hoy y mañana", "Día 1, 2, 3", "Imposible", "Mañana, mediodía, tarde"], "Ayer, hoy, mañana son siempre tres días consecutivos."],
    "TMP2_12": ["¿Cuánto es 1/2 de 2/3 de 3/4 de 4/5 de 100?", "Simplifica fracciones antes de la multiplicación.", ["20", "10", "50", "25"], "1/2 × 2/3 × 3/4 × 4/5 = 1/5. 1/5 × 100 = 20."],
    "TMP2_13": ["Un nenúfar duplica su superficie cada día. El día 20 llena el lago. ¿En qué día cubrió exactamente el 25%?", "Retroceder: dividir por 2 todos los días.", ["Día 18", "Día 5", "Día 15", "Día 10"], "Día 20: 100%. Día 19: 50%. Día 18: 25%."],
    "TMP2_14": ["Un ladrillo pesa 1 kg más la mitad del peso del ladrillo. ¿Cuanto pesa?", "Sea b el peso: b = 1 + b/2.", ["2 kilos", "1,5 kilogramos", "3 kilos", "1 kilogramo"], "b/2 = 1 → b = 2 kg."],
    "TMP2_15": ["6 hombres cavan 6 hoyos en 6 horas. ¿Cuánto tiempo les toma a 3 personas cavar 3 hoyos?", "¿Cuánto tiempo le toma a una persona hacer un agujero?", ["6 horas", "3 horas", "12 horas", "9 horas"], "Cada uno cava 1 hoyo en 6 horas. 3 personas, 3 hoyos en paralelo, también 6 horas."],
    "TMP2_16": ["¿Cuál es la siguiente letra: O, T, T, F, F, S, S,?", "En inglés: las iniciales de los números Uno, Dos, Tres…", ["mi", "norte", "t", "h"], "Uno, Dos, Tres, Cuatro, Cinco, Seis, Siete, Ocho → O, T, T, F, F, S, S, E."],
    "TMP2_17": ["Tienes 8 bolas: 7 iguales, una más pesada. Con una balanza ¿cuantos pesajes minimos para encontrarla?", "Divida en tres grupos, no en dos.", ["2", "3", "1", "4"], "3 contra 3; luego 1 vs 1 o del grupo difícil. Máximo 2 pesajes."],
    "TMP2_18": ["En una carrera adelantas al último. ¿En qué asiento estás?", "¿Quién está detrás del último?", ["es imposible", "el ultimo", "El penúltimo", "el primero"], "No hay nadie detrás del último; no puedes estar detrás de él para vencerlo."],
    "TMP2_19": ["3 gatos cazan 3 ratones en 3 minutos. ¿Cuánto tiempo les toma a 100 gatos atrapar 100 ratones?", "¿En cuántos minutos atrapa un gato un ratón?", ["3 minutos", "100 minutos", "33 minutos", "1 minuto"], "Cada uno atrapa 1 ratón en 3 minutos. Paralelamente, también 3 minutos."],
    "TMP2_20": ["¿Qué fracción de un día son 6 horas?", "¿Cuántas horas tiene el día?", ["1/4", "1/6", "1/3", "1/2"], "6/24 = 1/4."],
    "TMP3_1": ["6 máquinas fabrican 6 juguetes en 6 minutos. ¿Cuánto tiempo tardan 12 máquinas en fabricar 12 juguetes?", "¿En cuántos minutos una máquina fabrica un juguete?", ["6 minutos", "12 minutos", "3 minutos", "1 minuto"], "Cada uno hace 1 juguete en 6 minutos. 12 coches en paralelo, también 6 minutos."],
    "TMP3_2": ["El reloj marca las 6:00. ¿Cuál es el ángulo entre la manecilla de las horas y el minutero?", "¿Hacia dónde apuntan las lenguas a las 6:00 en punto?", ["180°", "90°", "120°", "360°"], "Manecilla de minutos a las 12, manecilla de horas a las 6: línea recta, 180°."],
    "TMP3_3": ["El reloj marca las 9:00. ¿Cuál es el ángulo entre las lenguas?", "¿Hacia dónde miran las lenguas a las 9 en punto?", ["90°", "180°", "270°", "45°"], "Manecilla de minutos a las 12, manecilla de horas a las 9: ángulo recto, 90°."],
    "TMP3_4": ["En una cuadrícula, columna 1 + columna 2 = columna 3. Filas: [3, 5, 8], [7, 2, 9], [4, 6,?]. Encuentra el número que falta.", "Aplica la misma regla a la tercera fila.", ["10", "8", "12", "6"], "4 + 6 = 10."],
    "TMP3_5": ["En una cuadrícula, columna 1 × columna 2 = columna 3. Filas: [2, 5, 10], [3, 4, 12], [6, 3,?]. Encuentra el número que falta.", "Multiplica las dos primeras columnas de la tercera fila.", ["18", "9", "15", "21"], "6 × 3 = 18."],
    "TMP3_6": ["Un caracol sube 4 m durante el día y se desliza 2 m durante la noche. La pared mide 12 m. ¿Cuántos días se necesitan para llegar a la cima?", "El último día podrá salir antes de regresar.", ["5 dias", "6 dias", "4 dias", "10 dias"], "Neto +2 m por ciclo. Después de 4 días: 8 m. El quinto día subir 8+4=12 m — llegar antes de que anochezca."],
    "TMP3_7": ["2 personas pintan 2 habitaciones en 2 horas. ¿Cuánto tiempo se tarda con 4 personas y 4 habitaciones?", "¿Cuántas horas pinta un hombre una habitación?", ["2 horas", "4 horas", "1 hora", "8 horas"], "Cada uno pinta 1 habitación en 2 horas. 4 personas, 4 cámaras en paralelo, también 2 horas."],
    "TMP3_8": ["Compras algo por $3 y lo vendes por $5. Luego compras algo más por $6 y lo vendes por $9. ¿Cuál es la ganancia total?", "El beneficio de cada transacción por separado.", ["$5", "$3", "$2", "$6"], "5−3=2, 9−6=3. Total $5."],
    "TMP3_9": ["Una rana salta 3 m hacia adelante y se desliza 1 m hacia atrás por ciclo. ¿Cuántos saltos hasta superar los 10 m?", "El último salto puede ser sin retroceso.", ["5 saltos", "4 saltos", "6 saltos", "10 saltos"], "Después de 4 ciclos: 8 m. Quinto salto: 8+3=11 m > 10. Entonces 5."],
    "TMP3_10": ["Tom tiene 3 veces la edad de Jim. Dentro de 10 años, Tom tendrá el doble de la edad de Jim. ¿Qué edad tiene Jim ahora?", "T = 3J; T+10 = 2(D+10).", ["10", "5", "15", "20"], "3J+10 = 2J+20 → J = 10."],
    "TMP3_11": ["Compras un caballo por $60, lo vendes por $70, lo vuelves a comprar por $80 y lo vendes por $90. ¿Beneficio total?", "Cada transacción por separado.", ["$20", "$10", "$30", "$0"], "+$10 luego +$10 = $20."],
    "TMP3_12": ["Doblas una hoja por la mitad 7 veces. ¿Cuántas capas?", "Cada pliegue duplica las capas.", ["128", "64", "14", "256"], "2⁷ = 128."],
    "TMP3_13": ["Un número primo multiplicado por sí mismo da 169. ¿Cuál es el número?", "La raíz cuadrada de 169.", ["13", "11", "17", "7"], "√169 = 13, que es primo."],
    "TMP3_14": ["Dos trenes están separados por 100 millas y cada uno se acerca a 50 mph. Una mosca vuela a 75 mph entre ellos. ¿Cuánto falta para que se encuentren los trenes?", "¿Cuánto falta para que se reúnan?", ["75 millas", "100 millas", "50 millas", "150 millas"], "Velocidad relativa 100 mph → 1 hora. Volar: 75 × 1 = 75 millas."],
    "TMP3_15": ["¿Cuál es el número más pequeño divisible por 1, 2, 3, 4, 5 y 6?", "Mínimo común múltiplo (CMMMC).", ["60", "30", "120", "720"], "CMMMC(1…6) = 60."],
    "TMP3_16": ["Contando del 1 al 100 ¿cuántas veces aparece el número 7?", "Unidades y decenas por separado.", ["20", "10", "11", "19"], "Unidades: 7,17,…,97 — 10. Decenas: 70–79 — 10. Total 20."],
    "TMP3_17": ["Un número aumenta un 20% y se convierte en 60. ¿Cuál era originalmente?", "1,2x = 60.", ["50", "48", "72", "40"], "x = 60 / 1,2 = 50."],
    "TMP3_18": ["Doblas una hoja por la mitad 10 veces. ¿Cuántas capas?", "Cada pliegue se duplica.", ["1024", "100", "512", "2048"], "2¹⁰ = 1024."],
    "TMP3_19": ["El producto de dos números enteros positivos consecutivos es 156. ¿Cuáles son?", "Dos números consecutivos cuyo producto es 156.", ["12 y 13", "11 y 12", "13 y 14", "10 y 15"], "12 × 13 = 156."],
    "TMP3_20": ["Cuadrado mágico de 3×3: cada fila, columna y diagonal suman 15. Primera fila [2, 7, 6], en medio [9, 5, 1]. ¿Cuál es el primer número de la última fila?", "La primera columna también suma 15.", ["4", "3", "6", "8"], "2+9+? = 15 → ? = 4."],
    "TMP4_1": ["Una colonia de bacterias se duplica cada hora y llena por completo un frasco al mediodía. ¿A qué hora estaba el tarro en cuarto?", "Retroceder: dividir por 2 cada hora.", ["10:00", "11:00", "9:00 am", "6:00"], "Mediodía: 100%. 11:00: 50%. 10:00: 25%."],
    "TMP4_2": ["Tienes 24 monedas; uno es falso y más fácil. ¿Cuántos pesajes mínimos en una báscula para saberlo con seguridad?", "Dividase en tres grupos en cada paso.", ["3", "4", "5", "2"], "8 contra 8, luego en el grupo ligero 3 contra 3, luego 1 contra 1: 3 pesajes."],
    "TMP4_3": ["Una cuerda se corta en 3 pedazos. Cada trozo se corta en 3 más pequeños. ¿Cuántas piezas en total?", "3×3.", ["9", "6", "12", "27"], "3 × 3 = 9."],
    "TMP4_4": ["Una lombriz está en el fondo de un pozo de 30 m. Sube 5 m durante el día y se desliza 4 m durante la noche. ¿En cuantos días sale?", "El último día sale sin deslizarse hacia atrás.", ["26 días", "30 dias", "25 dias", "27 dias"], "Neto +1 m/día. Después de 25 días: 25 m. Día 26: 25+5=30 m."],
    "TMP4_5": ["8 hombres construyen un muro en 10 días. ¿Cuántos días con 5 hombres?", "Trabajo total = personas × días.", ["16 dias", "12 dias", "20 dias", "8 dias"], "8×10 = 80 días-hombre. 80/5 = 16 días."],
    "TMP4_6": ["Los tubos A y B llenan un tanque en 6 h y 3 h respectivamente. ¿Cuánto tiempo permanecen abiertos ambos?", "Suma los caudales: 1/6 + 1/3 por hora.", ["2 horas", "4,5 horas", "3 horas", "1,5 horas"], "1/6+2/6=1/2 por hora → 2 horas."],
    "TMP4_7": ["Un rectángulo mide 3 veces más largo que ancho. El perímetro es de 48 m. ¿Cuál es el área?", "l = 3w; 2(w+3w)=48.", ["108 m²", "96 m²", "144 m²", "48 m²"], "8w=48 → w=6, l=18, área 108 m²."],
    "TMP4_8": ["Un número aumenta un 20% y luego disminuye un 20%. ¿Cuál es el cambio neto con respecto al original?", "Aplica los porcentajes uno a la vez.", ["4% de disminución", "0%", "4% de aumento", "2% de descuento"], "100→120→96. -4% neto."],
    "TMP4_9": ["La tienda aumenta los precios en un 25% y luego hace descuentos del 20%. ¿El cambio neto?", "1,25×0,80.", ["0% (sin cambios)", "+5%", "-5%", "+45%"], "1,25 × 0,80 = 1 — en su lugar."],
    "TMP4_10": ["¿La suma de los primeros 20 números naturales positivos?", "norte(norte+1)/2.", ["210", "200", "190", "220"], "20×21/2 = 210."],
    "TMP4_11": ["¿El ángulo entre las manecillas del reloj a las 4:30?", "El horario es entre las cuatro y media y las cinco.", ["45°", "90°", "60°", "30°"], "Minuto 180°, hora 135°, diferencia 45°."],
    "TMP4_12": ["El auto recorre 60 km a 30 km/h, luego 60 km a 60 km/h. ¿Velocidad media?", "Distancia total / tiempo total.", ["40 kilómetros por hora", "45 kilómetros por hora", "50 kilómetros por hora", "35 kilómetros por hora"], "2 h + 1 h = 3 h; 120/3 = 40 kilómetros por hora."],
    "TMP4_13": ["Si 2¹⁰ = 1024, ¿cuánto es 2¹²?", "2¹⁰ × 2².", ["4096", "2048", "8192", "1248"], "1024 × 4 = 4096."],
    "TMP4_14": ["Un grifo llena la piscina en 4 h; el drenaje lo aclara en 8 h. ¿Cuánto tiempo se tarda en llenar con ambos abiertos?", "Caudal neto = llenado − vaciado.", ["8 horas", "6 horas", "12 horas", "4 horas"], "1/4 − 1/8 = 1/8 por hora → 8 horas."],
    "TMP4_15": ["El precio baja un 10% y luego otro 10%. ¿La caída total del original?", "El segundo 10% corresponde al precio ya reducido.", ["19%", "20%", "18%", "21%"], "0,9×0,9=0,81 → 19% de disminución."],
    "TMP4_16": ["Encuentra x: 3x + 7 = 22.", "Aislar x.", ["5", "7", "3", "10"], "3x=15 → x=5."],
    "TMP4_17": ["Un tren de 100 m viaja a 50 m/s. ¿Cuánto tiempo les toma pasar completamente un poste?", "Se debe cubrir la longitud del tren.", ["2 segundos", "1 segundo", "4 segundos", "0,5 segundos"], "100/50 = 2 s."],
    "TMP4_18": ["Dos trabajadores terminan una obra en 12 días. Uno en 20 días. ¿Cuanto cuesta el otro solo?", "1/12 - 1/20.", ["30 dias", "24 dias", "15 dias", "40 dias"], "1/30 por día → 30 días."],
    "TMP4_19": ["Inviertes $1000 al 5% de interés simple por año, 3 años. ¿A cuánto asciende el interés total?", "Interés simple = capital × tasa × tiempo.", ["$150", "$1150", "$50", "$300"], "1000 × 0,05 × 3 = $150."],
    "TMP4_20": ["El granjero tiene gallinas y vacas. 20 cabezas y 56 pies. cuantas gallinas", "gramo + v = 20; 2g + 4v = 56.", ["12", "8", "14", "10"], "v=8, g=12."],
    "TMP5_1": ["Tienes dos cuerdas; cada uno se quema completamente en exactamente 1 hora, pero de manera irregular. ¿Cómo se miden exactamente 45 minutos?", "¿Qué pasa si enciendes una cuerda en ambos extremos?", ["Enciendes la cuerda 1 en ambos extremos y la cuerda 2 en un extremo, simultáneamente", "Enciendes ambas cuerdas en un extremo.", "Corta una cuerda en cuatro y enciende un trozo.", "Enciendes una cuerda, esperas a que se queme, luego la otra."], "La cuerda 1 (ambos extremos) se quema en 30 min. Luego enciende el otro extremo de la cuerda 2, otros 15 min. Total: 45 min."],
    "TMP5_2": ["Dos padres y dos hijos están comiendo. Come exactamente 3 huevos, uno cada uno. ¿Cómo es eso posible?", "¿Puede una persona desempeñar dos roles?", ["Abuelo, padre e hijo (3 personas)", "uno no comio", "Eran 4, pero los huevos fueron compartidos.", "Alguien se comió dos huevos"], "Tres generaciones: abuelo (padre), padre (e hijo y padre), hijo. Dos padres + dos hijos = 3 personas."],
    "TMP5_3": ["100 taquillas seguidas, todas cerradas con llave. El estudiante k cambia cada k-ésimo casillero. ¿Cuantos quedan abiertos al final?", "Un gabinete está abierto si se cambia un número impar de veces. ¿Qué números tienen un número impar de divisores?", ["10", "50", "25", "0"], "Sólo cuadrados perfectos: 1, 4, 9, 16, 25, 36, 49, 64, 81, 100 - 10 gabinetes."],
    "TMP5_4": ["Tres interruptores fuera de una habitación cerrada controlan tres bombillas en el interior. Puedes ingresar solo una vez. ¿Cómo saber quién es quién?", "Una bombilla que ha estado encendida durante mucho tiempo permanece caliente incluso después de apagarla.", ["Encienda 1, espere, apague; 2 ENCENDIDO; ingrese: calentar apagado=1, encendido=2, frío apagado=3", "Cambie uno a la vez y verifique cada vez", "Rápidamente enciendes y apagas los tres, luego ingresas", "Miras el ojo de la cerradura después de cada interruptor."], "1 ON por unos minutos, OFF, 2 ON, entrar. Caliente apagado = 1. Encendido = 2. Frío apagado = 3."],
    "TMP5_5": ["Tres cajas con la etiqueta \"Manzanas\", \"Naranjas\", \"Mezcla\". Todas las etiquetas están equivocadas. Puedes sacar una fruta de una caja. ¿De cuál?", "El cuadro «Mezcla» no puede contener mezcla, si todas las etiquetas son falsas.", ["cuadro \"mezclar\"", "caja \"manzana\"", "Caja de \"naranjas\"", "cualquier caja"], "Saca de la caja «Mezcla»: el contenido es homogéneo. Según la fruta, deduces el resto; las etiquetas «Manzanas» y «Naranjas» son falsas."],
    "TMP5_6": ["Un hombre tiene tres hijas. El producto de las edades es 36. La suma es el número de la casa vecina (ambigua). El mayor toca el piano. ¿Cuales son las edades?", "Dos tripletas de divisores de 36 tienen la misma suma. \"Más grande\" elimina un caso.", ["2, 2 y 9", "1, 6 y 6", "3, 3 y 4", "1, 4 y 9"], "Sumas 13: {1,6,6} y {2,2,9}. Hay un único «mayor» → {2, 2, 9}."],
    "TMP5_7": ["El problema de Monty Hall: eliges la puerta 1 de 3 (un coche, dos cabras). El anfitrión abre la puerta 3: cabra. ¿Se cambia en la puerta 2?", "¿Cuál era la probabilidad inicial de su puerta?", ["Sí, el cambio gana 2/3 de las veces", "No, es 50/50", "No importa", "No, la primera opción suele ser correcta"], "Tu elección: 1/3. La puerta restante es 2/3. El cambio duplica las posibilidades."],
    "TMP5_8": ["¿Cuántos cuadrados de cualquier tamaño hay en un tablero de ajedrez de 8×8?", "Cuente por separado 1×1, 2×2,… 8×8.", ["204", "64", "256", "100"], "8²+7²+…+1² = 204."],
    "TMP5_9": ["¿La suma de los números del 1 al 100?", "Fórmula de Gauss: n(n+1)/2.", ["5050", "5000", "10000", "10100"], "100×101/2 = 5050."],
    "TMP5_10": ["¿Cuántos ceros hay al final de 100?", "Los ceros provienen de los factores 10 = 2×5. Cuenta las potencias de 5.", ["24", "20", "25", "10"], "⌊100/5⌋ + ⌊100/25⌋ = 24."],
    "TMP5_11": ["El granjero cruza el río con el lobo, la cabra y la col. Barco: granjero + un artículo. El lobo se come a la cabra que se queda sola; la cabra se come el repollo. ¿Con qué empieza?", "¿Qué pareja puedes dejar sola en la orilla?", ["cabra", "el lobo", "repollo", "No importa"], "Primero la cabra. El lobo y el repollo están a salvo. Luego el resto con turnos."],
    "TMP5_12": ["A partir de un par de conejos, maduran en 1 mes y producen un nuevo par mensualmente después de la madurez. ¿Cuántos pares después de 6 meses?", "Secuencia de Fibonacci: 1, 1, 2, 3, 5, 8,…", ["8", "13", "6", "10"], "Mes 1 a 6: 1, 1, 2, 3, 5, 8 pares."],
    "TMP5_13": ["¿Número mínimo de movimientos en Torres de Hanoi con 5 discos?", "2ⁿ − 1, n = número de discos.", ["31", "32", "63", "15"], "2⁵ − 1 = 31."],
    "TMP5_14": ["¿Número mínimo de personas en una habitación de modo que haya >50% de probabilidad de que dos tengan el mismo cumpleaños?", "La paradoja del cumpleaños: la respuesta es menos de lo que parece.", ["23", "50", "183", "365"], "En 23 personas, la probabilidad supera el 50%."],
    "TMP5_15": ["En una sala de 23 personas, ¿cuál es la probabilidad aproximada de que al menos dos tengan el mismo cumpleaños?", "El resultado de la paradoja del cumpleaños.", ["alrededor del 50%", "alrededor del 6%", "alrededor del 25%", "alrededor del 75%"], "Con 23 personas, ~50,7%."],
    "TMP5_16": ["En una isla, los caballeros dicen la verdad y los delincuentes mienten. Decir: \"Ambos somos unos delincuentes\". ¿Qué es A?", "Si A fuera un caballero, ¿podría ser cierta la afirmación?", ["Estafador", "caballero", "No se puede determinar", "Ninguno"], "Un caballero no podría decir \"ambos estafadores\". Entonces A miente; la afirmación es falsa: no ambos son bandidos, el otro es un caballero."],
    "TMP5_17": ["¿La suma de los ángulos interiores de un heptágono (7 lados)?", "(norte - 2) × 180°.", ["900°", "720°", "1080°", "1260°"], "5 × 180° = 900°."],
    "TMP5_18": ["¿Cuántos cuadrados de cualquier tamaño hay en una cuadrícula de 4×4?", "1×1, 2×2, 3×3, 4×4.", ["30", "16", "20", "25"], "4²+3²+2²+1² = 30."],
    "TMP5_19": ["Lanzas una moneda justa 3 veces. ¿La probabilidad de que aparezca al menos una vez «cabeza»?", "El complemento: nunca cabeza (tres veces página).", ["7/8", "3/4", "1/2", "1/8"], "P(sin cabeza) = (1/2)³ = 1/8. P(al menos una cabeza) = 7/8."],
    "TMP5_20": ["¿Cuántos rectángulos hay en las líneas de una cuadrícula de 3×3 (4 horizontales, 4 verticales)?", "Eliges 2 horizontales y 2 verticales.", ["36", "18", "24", "9"], "C(4,2)² = 36."],
  }
});
